  var _agPricePollActive = false;
  var _agPricePollTimer  = null;
  var _agPricePollIdx    = 0;    // índice do próximo item a buscar (round-robin)
  var AG_PRICE_POLL_INTERVAL = 8000;  // 8s entre cada item = ~56s para ciclo completo (7 itens)

  // Buscar preço de UM item e salvar no cache
  var _agPollInFlight = {}; // itemType -> true enquanto há um fetch em andamento (evita race condition)
  async function agPollOneItem(itemType, force) {
    if (!force && agFloorCache[itemType] && Date.now() - agFloorCache[itemType].ts < AG_FLOOR_TTL) {
      return; // ainda válido, pular
    }
    if (_agPollInFlight[itemType]) return; // já há uma busca em andamento para este item — evita corrida
    _agPollInFlight[itemType] = true;
    try {
      const _q = encodeURIComponent(itemType);
      const pages = await Promise.all([
        fetch('/api/marketplace/listings?sort=cheap&currency=token&category=all&limit=20&offset=0&q='  + _q, { credentials: 'include' }).then(r => r.json()).catch(() => ({})),
        fetch('/api/marketplace/listings?sort=cheap&currency=token&category=all&limit=20&offset=20&q=' + _q, { credentials: 'include' }).then(r => r.json()).catch(() => ({})),
      ]);
      const all = pages.flatMap(d => (d.ok && Array.isArray(d.listings)) ? d.listings : []);
      // IMPORTANTE: a API não filtra por item específico no servidor (só por categoria ampla),
      // então o filtro por itemType precisa ser feito aqui no cliente
      let valid = all.filter(l => String(l.itemType||'') === itemType && String(l.currency||'').toLowerCase() === 'token' && Number(l.priceUsd) > 0 && Number(l.quantity) > 0);
      if (!valid.length) return;
      valid.sort((a, b) => Number(a.priceUsd)/Number(a.quantity) - Number(b.priceUsd)/Number(b.quantity));

      // Filtro de quantidade mínima — ignora anúncios pequenos que distorcem o FLOOR
      const _minQty = agGetFloorMinQty(itemType);
      let _ignoredCount = 0;
      let _ignoredSample = [];
      if (_minQty > 0) {
        const _ignored  = valid.filter(l => Number(l.quantity) < _minQty);
        const _filtered = valid.filter(l => Number(l.quantity) >= _minQty);
        _ignoredCount  = _ignored.length;
        _ignoredSample = _ignored.slice(0, 4).map(l => Number(l.quantity) + 'x @ $' + (Number(l.priceUsd)/Number(l.quantity)).toFixed(8));
        if (_filtered.length > 0) {
          valid = _filtered; // usa só os que batem o mínimo
        }
        // Se nenhum anúncio atinge o mínimo, mantém todos como fallback (evita ficar sem FLOOR)
      }

      const best = valid[0];
      const unitPrice = Number(best.priceUsd) / Number(best.quantity);

      // Sanity check: descarta resultado se o preço mudou de forma absurda vs o cache anterior
      // (proteção contra listings de outro item vazando pela busca textual da API)
      const _prevCached = agFloorCache[itemType];
      if (_prevCached && _prevCached.price > 0) {
        const _ratio = unitPrice / _prevCached.price;
        if (_ratio > 50 || _ratio < 0.02) {
          AG_LOG.warn('[PricePoller] ' + itemType + ': preço suspeito $' + unitPrice.toFixed(8) +
            ' (anterior $' + _prevCached.price.toFixed(8) + ', ratio=' + _ratio.toFixed(2) + 'x) — ignorando, mantendo cache anterior');
          return;
        }
      }

      agFloorCache[itemType] = {
        price:    unitPrice,
        seller:   best.sellerName || best.seller || '?',
        qty:      Number(best.quantity),
        ts:       Date.now(),
        floorIsBlacklisted: false,
        ignoredCount: _ignoredCount,
        ignoredSample: _ignoredSample,
      };
      if (_minQty > 0 && _ignoredCount > 0) {
        AG_LOG.info('[PricePoller] ' + itemType + ': $' + unitPrice.toFixed(8) + '/un (qty=' + Number(best.quantity) +
          ') — ignorados ' + _ignoredCount + ' anúncio(s) < ' + _minQty + ': ' + _ignoredSample.join(', '));
      } else {
        AG_LOG.debug('[PricePoller] ' + itemType + ': $' + unitPrice.toFixed(8) + '/un');
      }
    } catch(e) { AG_LOG.warn('[PricePoller] erro ao buscar ' + itemType + ': ' + e.message); }
    finally { _agPollInFlight[itemType] = false; }
  }

  // Poller round-robin: 1 item a cada 8s
  function agStartPricePoller() {
    if (_agPricePollTimer) return;
    // Fazer uma rodada inicial sequencial com delay entre items
    (async function initialRound() {
      for (var i = 0; i < AG_PRICE_ITEMS.length; i++) {
        await agPollOneItem(AG_PRICE_ITEMS[i]);
        if (i < AG_PRICE_ITEMS.length - 1) {
          await new Promise(r => setTimeout(r, 2000)); // 2s entre cada item na init
        }
      }
      AG_LOG.info('[PricePoller] Cache inicial completo (' + AG_PRICE_ITEMS.length + ' itens)');
    })();

    // Poller contínuo: 1 item a cada 8s (round-robin)
    _agPricePollTimer = setInterval(function() {
      var item = AG_PRICE_ITEMS[_agPricePollIdx % AG_PRICE_ITEMS.length];
      _agPricePollIdx++;
      agPollOneItem(item);
    }, AG_PRICE_POLL_INTERVAL);
    AG_LOG.info('[PricePoller] Iniciado — 1 req/' + (AG_PRICE_POLL_INTERVAL/1000) + 's, ciclo ~' + Math.round(AG_PRICE_ITEMS.length * AG_PRICE_POLL_INTERVAL / 1000) + 's');
  }

  function agStopPricePoller() {
    if (_agPricePollTimer) { clearInterval(_agPricePollTimer); _agPricePollTimer = null; }
  }

  // Ler preço do cache (síncrono — sem fetch)
  function agGetCachedPrice(itemType) {
    const c = agFloorCache[itemType];
    return c ? c : null;
  }

  // ── Blacklist de players ──────────────────────────────────────────────────
  function agGetBlacklist() {
    try { return JSON.parse(localStorage.getItem('ag_sell_blacklist') || '[]'); } catch(_) { return []; }
  }
  function agSetBlacklist(list) {
    localStorage.setItem('ag_sell_blacklist', JSON.stringify(list));
  }
  function agIsBlacklisted(sellerName) {
    if (!sellerName) return false;
    const list = agGetBlacklist();
    const name = String(sellerName).toLowerCase().trim();
    return list.some(function(n) { return String(n).toLowerCase().trim() === name; });
  }
  function agRenderBlacklistTags() {
    const host = document.getElementById('ag-panel-host');
    const sr   = host && host.shadowRoot;
    const el   = sr && sr.getElementById('as-blacklist-tags');
    if (!el) return;
    const list = agGetBlacklist();
    el.innerHTML = list.length === 0
      ? '<span style="font-size:10px;color:#667;font-style:italic">Nenhum</span>'
      : list.map(function(n) {
          return '<span style="font-size:10px;background:rgba(239,68,68,0.15);border:1px solid rgba(239,68,68,0.3);color:#f87171;border-radius:4px;padding:1px 6px;cursor:pointer" data-name="' + n + '" title="Clique para remover">&#10005; ' + n + '</span>';
        }).join('');
    el.querySelectorAll('span[data-name]').forEach(function(tag) {
      tag.addEventListener('click', function() {
        var list2 = agGetBlacklist().filter(function(n) { return n !== tag.dataset.name; });
        agSetBlacklist(list2);
        agRenderBlacklistTags();
        AG_LOG_SELL.info('Blacklist: removido "' + tag.dataset.name + '"');
      });
    });
  }
  function agOpenBlacklistEditor() {
    var current = agGetBlacklist().join(', ');
    var input = prompt('Players na blacklist (separados por virgula):\nEx: Ze1, Ze2, MinhaOutraConta', current);
    if (input === null) return;
    var parsed = input.split(',').map(function(s) { return s.trim(); }).filter(Boolean);
    agSetBlacklist(parsed);
    agRenderBlacklistTags();
    AG_LOG_SELL.info('Blacklist atualizada: ' + (parsed.length ? parsed.join(', ') : '(vazia)'));
  }

  async function agFetchFloor(itemType, force) {
    const cached = agFloorCache[itemType];
    if (!force && cached && Date.now() - cached.ts < AG_FLOOR_TTL) return cached;
    // Evita corrida com agPollOneItem (poller round-robin) buscando o mesmo item ao mesmo tempo
    if (_agPollInFlight[itemType]) {
      // Já tem uma busca em andamento — aguarda um pouco e retorna o cache (mesmo que stale)
      await new Promise(r => setTimeout(r, 1200));
      return agFloorCache[itemType] || null;
    }
    _agPollInFlight[itemType] = true;
    try {
      // Fetch multiple pages to find true cheapest per unit
      // API sorts by total price — need enough results to catch large-qty cheap listings
      const _q = encodeURIComponent(itemType);
      const pages = await Promise.all([
        fetch('/api/marketplace/listings?sort=cheap&currency=token&category=all&limit=20&offset=0&q='  + _q, {credentials:'include'}).then(r=>r.json()).catch(()=>({})),
        fetch('/api/marketplace/listings?sort=cheap&currency=token&category=all&limit=20&offset=20&q=' + _q, {credentials:'include'}).then(r=>r.json()).catch(()=>({})),
      ]);
      const allListings = pages.flatMap(d => (d.ok && Array.isArray(d.listings)) ? d.listings : []);
      if (!allListings.length) return null;
      // Filter valid token listings — IMPORTANTE: a API não filtra por item específico no
      // servidor (só por categoria ampla), então o filtro por itemType precisa ser feito aqui
      const tok = allListings.filter(l =>
        String(l.itemType||'') === itemType &&
        String(l.currency||'').toLowerCase() === 'token' &&
        Number(l.priceUsd) > 0 &&
        Number(l.quantity) > 0
      );
      if (!tok.length) return null;
      // Sort by unit price ascending
      const withUnit = tok.map(l => ({
        unitPrice: Number(l.priceUsd) / Number(l.quantity),
        seller:    l.sellerDisplayName || l.sellerName || '?',
        qty:       Number(l.quantity),
        total:     Number(l.priceUsd),
      }));
      withUnit.sort((a, b) => a.unitPrice - b.unitPrice);

      // Filtro de quantidade mínima — ignora anúncios pequenos que distorcem o FLOOR
      // (mesma regra usada em agPollOneItem; aplica-se só a wood/coal/stone/metal se configurado)
      let withUnitFiltered = withUnit;
      const _minQty = agGetFloorMinQty(itemType);
      let _ignoredCount = 0, _ignoredSample = [];
      if (_minQty > 0) {
        const _ignored  = withUnit.filter(l => l.qty < _minQty);
        const _filtered = withUnit.filter(l => l.qty >= _minQty);
        _ignoredCount  = _ignored.length;
        _ignoredSample = _ignored.slice(0, 4).map(l => l.qty + 'x @ $' + l.unitPrice.toFixed(8));
        if (_filtered.length > 0) withUnitFiltered = _filtered;
        // Se nenhum anúncio atinge o mínimo, mantém todos como fallback
      }

      const best = withUnitFiltered[0];

      // Sanity check: descarta se o preço mudou de forma absurda vs o cache anterior
      const _prevCached2 = agFloorCache[itemType];
      if (_prevCached2 && _prevCached2.price > 0) {
        const _ratio2 = best.unitPrice / _prevCached2.price;
        if (_ratio2 > 50 || _ratio2 < 0.02) {
          AG_LOG.warn('agFetchFloor: ' + itemType + ' preço suspeito $' + best.unitPrice.toFixed(8) +
            ' (anterior $' + _prevCached2.price.toFixed(8) + ') — mantendo cache anterior');
          return _prevCached2;
        }
      }

      const floorIsBlacklisted = agIsBlacklisted(best.seller);
      if (floorIsBlacklisted) {
        AG_LOG_SELL.info('Floor de "' + best.seller + '" esta na blacklist — vendendo no mesmo preco (sem undercut)');
      }
      if (_minQty > 0 && _ignoredCount > 0) {
        AG_LOG.info('Floor ' + itemType + ': $' + best.unitPrice.toFixed(8) + '/un x' + best.qty + ' (' + best.seller +
          ') — ignorados ' + _ignoredCount + ' anúncio(s) < ' + _minQty + ': ' + _ignoredSample.join(', '));
      } else {
        AG_LOG.debug('Floor ' + itemType + ': $' + best.unitPrice.toFixed(8) + '/un x' + best.qty + ' (' + best.seller + ') blacklisted=' + floorIsBlacklisted + ' [' + tok.length + ' listings]');
      }
      const result = { price: best.unitPrice, seller: best.seller, qty: best.qty, ts: Date.now(), floorIsBlacklisted, ignoredCount: _ignoredCount, ignoredSample: _ignoredSample };
      agFloorCache[itemType] = result;
      agPriceCache[itemType] = best.unitPrice;
      return result;
    } catch(e) {
      AG_LOG.warn('agFetchFloor erro', itemType, e);
      return null;
    } finally {
      _agPollInFlight[itemType] = false;
    }
  }

  function agFmtFloor(v) {
    let s = v.toFixed(10), i = s.length-1;
    while(i>0 && s[i]==='0') i--;
    if(s[i]==='.') i--;
    return '$'+s.slice(0,i+1);
  }


  function agStatsReset() {
    agStats.items = 0; agStats.startMs = Date.now(); agUpdateRateDisplay();
  }
  function agStatsAdd(n = 1) {
    agStats.items += n;
    agUpdateRateDisplay();
    // Registra timestamp do último item recebido durante coleta ativa
    if (agActive && (Da === 'mining' || _agChopState === 'chopping')) {
      agMiningLastItemAt = Date.now();
    }
  }

  // Contadores separados para modo rock misto
  const agRockSubStats = { stone: 0, coal: 0, metal: 0, wood: 0 };
  function agRockSubReset() { agRockSubStats.stone = 0; agRockSubStats.coal = 0; agRockSubStats.metal = 0; agRockSubStats.wood = 0; }

  // Monkey-patch pu para contar itens reais
  let _agOrigAddResource = null;
  // ── Monkey-patch handleResourceEvent para detectar sinais de tile bugado ────
  let _agOrigHandleResourceEvent = null;
  let _agLastHarvHitAt           = 0;   // timestamp do último harv_hit enviado pelo bot
  let _agHarvHitResponseAt       = 0;   // timestamp do último res_evt 'wear' recebido
  let _agHarvHitNoResponseTimer  = null;

  function agInstallResourceEventMonitor() {
    if (_agOrigHandleResourceEvent || typeof handleResourceEvent === 'undefined') return;
    _agOrigHandleResourceEvent = handleResourceEvent;
    handleResourceEvent = function(d) {
      // Chama original primeiro
      _agOrigHandleResourceEvent(d);

      if (!agActive) return;
      if (!agLastKey) return;

      try {
        // ── Sinal 1: wear SEM loot para nós (outro jogador bateu ou servidor ignorou) ──
        if (d.evt === 'wear') {
          _agHarvHitResponseAt = Date.now();
          var ourHit = (localPlayerId != null && Number(d.by) === Number(localPlayerId));
          var hasLoot = !!d.loot;
          var keys = (d.keys || []).map(String);
          var isOurTarget = keys.some(function(k){ return k === agLastKey; });

          if (isOurTarget && ourHit && !hasLoot) {
            AG_LOG.warn('🔍 TILE DEBUG: wear sem loot para nós | key=' + agLastKey +
              ' | m=' + d.m + '/' + d.hm +
              ' | by=' + d.by + '(nós=' + localPlayerId + ')' +
              ' | state=' + (Da||io) +
              ' | isso pode indicar tile bugado se repetir');
          }

          // ── Sinal 2: wearHits > wearMax (inconsistência servidor/cliente) ──
          if (isOurTarget) {
            var ctx3 = R3();
            var rd3  = ctx3 && ctx3.rockMap && ctx3.rockMap.get(agLastKey);
            if (rd3 && Number(d.m) > Number(d.hm) && d.hm > 0) {
              AG_LOG.warn('🔍 TILE DEBUG: m > hm — inconsistência servidor/cliente | key=' + agLastKey +
                ' | servidor diz m=' + d.m + ' hm=' + d.hm +
                ' | tile pode estar dessincronizado');
            }
            // ── Sinal 3: m === hm mas sem clear subsequente (aguarda 3s) ──
            if (Number(d.m) >= Number(d.hm) && d.hm > 0) {
              var _k3 = agLastKey;
              setTimeout(function() {
                if (!agActive || agLastKey !== _k3) return;
                // Se ainda estamos minerando a mesma key depois do m===hm, é bugado
                if (Da === 'mining' || _agChopState === 'chopping') {
                  AG_LOG.warn('🔍 TILE DEBUG: m===hm mas clear não chegou em 3s | key=' + _k3 +
                    ' | Fa=' + _agMineState + ' _agChopState=' + _agChopState +
                    ' | possível tile ressincronizado no servidor mas não no cliente');
                }
              }, 3000);
            }
          }
        }

        // ── Sinal 4: clear inesperado (pedra limpa por outro jogador) ──
        if (d.evt === 'clear') {
          var clearKeys = (d.keys || []).map(String);
          var wasOurTarget = clearKeys.some(function(k){ return k === agLastKey; });
          if (wasOurTarget && _agMineState !== 'mining' && _agChopState !== 'chopping') {
            AG_LOG.info('🔍 TILE DEBUG: clear recebido para nosso target mas não estávamos minerando | key=' + agLastKey +
              ' | Fa=' + _agMineState + ' _agChopState=' + _agChopState +
              ' | pedra foi coletada por outro jogador enquanto nos aproximávamos');
          }
        }

        // ── Sinal 5: resposta demorou > 5s após harv_hit ──
        if (d.evt === 'wear' && _agLastHarvHitAt > 0) {
          var latency = Date.now() - _agLastHarvHitAt;
          if (latency > 5000) {
            AG_LOG.warn('🔍 TILE DEBUG: latência alta de resposta | delay=' + Math.round(latency/1000) + 's' +
              ' | key=' + agLastKey + ' | pode indicar lag de servidor ou tile bugado');
          }
        }

      } catch(_) {}
    };
    AG_LOG.info('Monitor de tile bugado instalado (handleResourceEvent patched)');
  }

  function agUninstallResourceEventMonitor() {
    if (!_agOrigHandleResourceEvent) return;
    handleResourceEvent = _agOrigHandleResourceEvent;
    _agOrigHandleResourceEvent = null;
  }

  // Expor timestamp do último harv_hit para o monitor de latência
  var _origSendHarvestHit = null;
  function agInstallHarvHitMonitor() {
    if (_origSendHarvestHit || typeof jbe === 'undefined') return;
    _origSendHarvestHit = jbe;
    /* sendHarvestHit intercept N/A in minified bundle */
  if(false) sendHarvestHit = function(kind, keys, hasCoal, hasMetal) {
      if (agActive) _agLastHarvHitAt = Date.now();
      return _origSendHarvestHit.apply(this, arguments);
    };
  }

  function agInstallResourceCounter() {
    if (_agOrigAddResource) return;
    _agOrigAddResource = Su;
    Su = function(type, amt, opts) {
      if (agActive) {
        const n = Number(amt) || 1;
        const tracked =
          (agMode === 'tree'       && type === 'wood')  ||
          (agMode === 'rock'       && (type === 'stone' || type === 'coal' || type === 'metal')) ||
          (agMode === 'rock_stone' && type === 'stone') ||
          (agMode === 'rock_coal'  && type === 'coal')  ||
          (agMode === 'fish'       && type === 'fish') ||
          (agMode === 'tree_coal' && (type === 'wood' || type === 'coal')) ||
          (agMode === 'tree_rock'  && (type === 'wood' || type === 'coal' || type === 'stone')) ||
          (agMode === 'all'        && (type === 'wood' || type === 'coal' || type === 'stone' || type === 'metal'));
        if (tracked) {
          agStatsAdd(n);
          // Subcategoria para modo misto
          if ((agMode === 'rock' || agMode === 'tree_coal' || agMode === 'tree_rock' || agMode === 'all') && agRockSubStats[type] !== undefined) {
            agRockSubStats[type] += n;
          }
        }
      }
      return _agOrigAddResource.call(this, type, amt, opts);
    };
  }
  function agUninstallResourceCounter() {
    if (!_agOrigAddResource) return;
    Su = _agOrigAddResource;
    _agOrigAddResource = null;
  }

  // Média ponderada por volume dos últimos N dias com vendas
  function agWeightedRecentPrice(samples, n = 5) {
    const recent = [...samples].reverse().filter(s => (Number(s.sales)||0) > 0).slice(0, n);
    if (!recent.length) return null;
    let sumW = 0, sumS = 0;
    for (const s of recent) {
      const sales = Number(s.sales) || 0;
      sumW += (Number(s.avgUnitPrice) || 0) * sales;
      sumS += sales;
    }
    return sumS > 0 ? sumW / sumS : null;
  }

  async function agFetchPrice(itemType) {
    const cached = agFloorCache[itemType];
    if (cached && Date.now() - cached.ts < AG_FLOOR_TTL) return cached.price;
    const result = await agFetchFloor(itemType);
    if (result) { agUpdateRateDisplay(); return result.price; }
    return null;
  }

  function agItemType() {
    if (agMode === 'tree')       return 'wood';
    if (agMode === 'rock')       return 'stone'; // misto stone+coal
    if (agMode === 'rock_stone') return 'stone';
    if (agMode === 'rock_coal')  return 'coal';
    if (agMode === 'tree_coal') return 'wood'; // wood como referencia
    if (agMode === 'all')       return 'wood'; // referencia para stats
    if (agMode === 'fish')       return 'fish';
    return null;
  }

  // Retorna true se o modo atual coleta pedras (qualquer subtipo de rock)
  function agIsRockMode() {
    return agMode === 'rock' || agMode === 'rock_stone' || agMode === 'rock_coal';
    // Note: 'all' handles tool switching dynamically
  }

  function fmtUsd(v) {
    if (!v || v === 0) return '$0.0000';
    if (v >= 0.01) return '$' + v.toFixed(4);
    // Sem notação científica: toFixed com casas suficientes, remove zeros à direita
    let s = v.toFixed(10);
    let i = s.length - 1;
    while (i > 0 && s[i] === '0') i--;
    if (s[i] === '.') i--;
    return '$' + s.slice(0, i + 1);
  }

  /** Formata valor $/m — 2 casas decimais significativas, sem notação científica */
  function fmtUsdH(v) {
    if (!v || v === 0) return '$0.00';
    if (v >= 1)     return '$' + v.toFixed(2);
    if (v >= 0.01)  return '$' + v.toFixed(3);
    if (v >= 0.001) return '$' + v.toFixed(4);
    // Para valores muito pequenos: 2 dígitos significativos
    const exp = Math.floor(Math.log10(Math.abs(v)));
    return '$' + v.toFixed(Math.max(0, -exp + 1));
  }

  function agUpdateRateDisplay() {
    const host = document.getElementById('ag-panel-host');
    const el = host?.shadowRoot?.getElementById('ag-rate');
    if (!el) return;
    if (!agActive || agStats.items === 0) { el.innerHTML = ''; return; }
    const elMin   = (Date.now() - agStats.startMs) / 60000;
    const perHour = elMin > 0.016 ? Math.round(agStats.items / elMin * 60) : null;
    const price   = agPriceCache[agItemType()];
    // Modo rock misto ou tree_coal: mostra separados
    if ((agMode === 'rock' || agMode === 'tree_coal' || agMode === 'tree_rock' || agMode === 'all') && (agRockSubStats.stone > 0 || agRockSubStats.coal > 0 || agRockSubStats.wood > 0 || agRockSubStats.metal > 0)) {
      const elMin2 = (Date.now() - agStats.startMs) / 60000;
      function phR(n) { return elMin2 > 0.016 ? Math.round(n / elMin2 * 60) : null; }
      function priceRow(type, label, count) {
        const ph = phR(count);
        const pr = agPriceCache[type];
        let row = `<span style="color:#8a93a8">${label}</span> <span style="color:#d4d8e2">${count}`;
        if (ph != null) row += ` · ${ph}/m`;
        row += '</span>';
        if (pr != null && ph != null) row += ` <span style="color:#a7f3d0">${fmtUsd(ph * pr)}/m</span>`;
        return `<div style="display:flex;justify-content:space-between;gap:8px;margin-top:2px">${row}</div>`;
      }
      let html = '<div style="font-weight:700;margin-bottom:3px">&#128230; ' + agStats.items + ' coletados' + (perHour!=null?' · ' + perHour + '/m':'') + '</div>';
      function resImg(src) { return '<img src="' + src + '" width="14" height="14" style="vertical-align:middle;margin-right:3px;image-rendering:pixelated" draggable="false">'; }
      if (agRockSubStats.wood  > 0) html += priceRow('wood',  resImg('/assets/hud/resources/wood.png')  + 'Wood',  agRockSubStats.wood);
      if (agRockSubStats.stone > 0) html += priceRow('stone', resImg('/assets/hud/resources/stone.png') + 'Stone', agRockSubStats.stone);
      if (agRockSubStats.coal  > 0) html += priceRow('coal',  resImg('/assets/hud/resources/coal.png')  + 'Coal',  agRockSubStats.coal);
      if (agRockSubStats.metal > 0) html += priceRow('metal', resImg('/assets/hud/resources/metal.png') + 'Metal', agRockSubStats.metal);
      // Total $ se tiver preços
      const phTotal = perHour;
      const totalUsd = (() => {
        let t = 0; let ok = true;
        for (const [type, count] of Object.entries(agRockSubStats)) {
          if (!count) continue;
          if (agMode === 'tree_coal' && type !== 'wood' && type !== 'coal') continue;
          if (agMode === 'rock' && type === 'wood') continue;
          const pr = agPriceCache[type];
          if (pr == null) { ok = false; break; }
          const ph2 = phR(count);
          if (ph2 == null) { ok = false; break; }
          t += ph2 * pr;
        }
        return ok && t > 0 ? t : null;
      })();
      if (totalUsd != null) {
        html += `<div style="margin-top:4px;padding-top:3px;border-top:1px solid rgba(255,255,255,0.07);display:flex;justify-content:space-between">
          <span style="color:#7eb8f7;font-weight:700">&#128176; Total</span>
          <span style="color:#a7f3d0;font-weight:700">${fmtUsd(totalUsd)}/m</span>
        </div>`;
      }
      el.innerHTML = html;
      return;
    }

    const itemType = agItemType();
    let html = '&#128230; ' + agStats.items + ' coletados' + (perHour != null ? ' · ' + perHour + '/m' : '');
    if (price === undefined) {
      html += '<br><span style="color:#556">$ buscando preco...</span>';
    } else if (price === null) {
      html += '<br><span style="color:#556">$ sem dados de preco</span>';
    } else if (perHour != null) {
      html += '<br><span style="color:#a7f3d0">$ ' + fmtUsd(perHour * price) + '/m</span>';
      const _flr = agFloorCache[itemType];
      const sellerInfo = _flr ? ' <span style="color:#334">(' + _flr.seller + ')</span>' : '';
      html += '<br><span style="color:#667">&#128204; ' + agFmtFloor(price) + '/un' + sellerInfo + '</span>';
    }
    el.innerHTML = html;
  }

  function agStartRateTimer() {
    clearInterval(agRateTimer);
    agRateTimer = setInterval(agUpdateRateDisplay, 3000);
    const t = agItemType(); if (t) agFetchPrice(t);
  }
  function agStopRateTimer() { clearInterval(agRateTimer); agRateTimer = null; }

  // ── Tools ──────────────────────────────────────────────────────────────────
  const AG_TOOLS = {
    tree: ['tool_axe_l2', 'tool_axe'],
    rock: ['tool_pickaxe_l2', 'tool_pickaxe'],
    fish: ['tool_fishing_rod'],
  };

  function agFindToolSlot() {
    // tree_coal: retorna machado (hint mostra o que temos)
    const tools = AG_TOOLS[agMode] || (agIsRockMode() ? AG_TOOLS['rock'] : (agMode === 'tree_coal' ? AG_TOOLS['tree'] : []));
    for (const t of tools)
      for (let i = 0; i < De.length; i++) {
        const s = De[i];
        if (s && s.type === t && (s.count||0) > 0) return i;
      }
    return -1;
  }

  function agEnsureTool() {
    // tree_coal is handled separately in agApproach via resType — skip here
    if (agMode === 'tree_coal' || agMode === 'tree_rock' || agMode === 'all') return true;
    const needed = agMode === 'tree' ? AG_TOOLS['tree']
                 : agIsRockMode()    ? AG_TOOLS['rock']
                 : AG_TOOLS['fish']  || ['tool_fishing_rod'];
    if (!needed) return false;
    const current = Yn();
    if (needed.includes(current)) return true;
    // Procurar ferramenta na hotbar e equipar
    for (const t of needed) {
      for (let i = 0; i < De.length; i++) {
        const s = De[i];  // Fe = hotbarSlots, não Oe
        if (s && s.type === t && (s.count||0) > 0) {
          AG_LOG.info('agEnsureTool: trocando slot ' + i + ' (' + t + ') | era: ' + current);
          (function(){ try { an=i; kt(); } catch(_){} })();
          return true;
        }
      }
    }
    AG_LOG.warn('agEnsureTool: sem ferramenta na hotbar | needed=' + needed.join('/') + ' | current=' + current);
    return false;
  }

  function agRefreshHint() {
    if (!agHintEl) return;
    const slot = agFindToolSlot();
    const names = { tree:'Machado', rock:'Picareta', rock_stone:'Picareta', rock_coal:'Picareta', fish:'Fishing Rod' };
    const toolName = names[agMode] || 'Picareta';
    if (slot === -1) {
      agHintEl.textContent = '⚠ ' + toolName + ' nao esta na hotbar';
      agHintEl.style.color = '#e05';
    } else {
      const s = De[slot];
      var toolSrc = s && s.type ? {
        'tool_axe':'/assets/hud/tools/axe.png', 'tool_axe_l2':'/assets/hud/tools/axelvl2.png',
        'tool_pickaxe':'/assets/hud/tools/pickaxe.png', 'tool_pickaxe_l2':'/assets/hud/tools/pickaxelvl2.png',
        'tool_fishing_rod':'/assets/hud/tools/fishingrod.png'
      }[s.type] : null;
      var toolImg = toolSrc ? '<img src="' + toolSrc + '" width="13" height="13" style="vertical-align:middle;margin-right:3px;image-rendering:pixelated" draggable="false">' : '';
      agHintEl.innerHTML = toolImg + (s&&s.type.includes('_l2')?toolName+' L2':toolName) + ' — slot ' + (slot+1);
      agHintEl.style.color = '#3d9';
    }
    if (agActive) agUpdateRateDisplay();
  }

  // ── State ──────────────────────────────────────────────────────────────────
  function agSetStatus(msg) { if (agStatusEl) agStatusEl.textContent = msg; }

  function agIsBusy() {
    try {
      // Diálogo NPC aberto — body tem classe kintara-dialogue-open
      if (document.body && document.body.classList.contains('kintara-dialogue-open')) return true;
      // Mapa cheio aberto — fullmap legend visível
      const fullmap = document.querySelector('.kintara-fullmap-legend');
      if (fullmap) {
        const fr = fullmap.getBoundingClientRect();
        if (fr.width > 0 && fr.height > 0) return true;
      }
      // Player stunado no wild
      if (ms()) return true;
    } catch (_) {}
    return false;
  }

  function agInventoryFull() {
    try {
      const max = INVENTORY_MUX_STACK || 999;
      const t   = agMode === 'tree'       ? 'wood'
                : agMode === 'rock'       ? 'stone'  // misto: checa stone (conservador)
                : agMode === 'rock_stone' ? 'stone'
                : agMode === 'rock_coal'  ? 'coal'
                : 'fish';
      for (let i = 0; i < 24; i++) {
        const s = st[i];
        if (!s || !s.type) return false;
        if (s.type === t && (s.count||0) < max) return false;
      }
      for (let i = 0; i < De.length; i++) {
        const s = De[i];
        if (!s || !s.type) return false;
        if (s.type === t && (s.count||0) < max) return false;
      }
      return true;
    } catch (_) { return false; }
  }

  // ── Resource map ───────────────────────────────────────────────────────────
  function agGetMap() {
    const ctx = R3();
    if (!ctx) return null;
    if (agMode === 'tree') return ctx.treeMap;
    if (agMode === 'rock' || agMode === 'rock_stone' || agMode === 'rock_coal') return ctx.rockMap;
    if (agMode === 'fish') return null;
    // all, tree_rock, tree_coal, tree_coal_rock — combina treeMap + rockMap
    const combined = new Map();
    if (ctx.treeMap) for (const [k,v] of ctx.treeMap) combined.set(k, v);
    if (ctx.rockMap) for (const [k,v] of ctx.rockMap) combined.set(k, v);
    return combined.size > 0 ? combined : null;
  }

  // Verifica se um rock data é coletável no modo atual
  function agRockMatches(data) {
    if (agMode === 'rock')       return true;                     // qualquer pedra
    if (agMode === 'rock_stone') return !data.hasCoal && !data.hasMetal; // só stone pura
    if (agMode === 'rock_coal' || agMode === 'tree_coal') return !!data.hasCoal;
    if (agMode === 'tree_rock') return true; // stone + coal
    if (agMode === 'all') return true;       // tudo
    return false;
  }

  function agIsRecentlyHarvested(key) {
    return agHarvestDone && agHarvestDone.key === key &&
      (Date.now() - agHarvestDone.ot) < (agOptCfg.harvestMs || AG_HARVEST_COOLDOWN);
  }
  function agMarkHarvested(key) { agHarvestDone = { key, ot: Date.now() }; }

  function agPrimaryKey(key, data) {
    return (agIsRockMode() && data.keys && data.keys.length > 0) ? data.keys[0] : key;
  }

  /**
   * Score para modo rock — considera cluster size, floor price e tipo (coal > stone).
   * Substitui agFindNearest para modos rock/rock_stone/rock_coal.
   */
  function agRockScore(data, dist) {
    // Delega ao agOptScore (sistema atual baseado em agOptCfg.priority)
    // AG_OPT_FLOOR_REF foi removido na refatoração — floor price não é mais usado
    var clusterSize = (data.keys && data.keys.length) || 1;
    var type = data.hasCoal ? 'coal' : data.hasMetal ? 'metal' : 'stone';
    return agOptScore(type, dist, clusterSize);
  }

  /**
   * Encontra o recurso mais próximo considerando a DISTÂNCIA _agAO TILE DE ABORDAGEM,
   * não ao recurso em si. Isso garante que selecionamos o recurso que requer
   * menor deslocamento real do personagem, e sempre requer movimento.
   */
  function agFindNearest() {
    const map = agGetMap();
    if (!map || map.size === 0) return null;
    const blk  = d();
    const seen  = new Set();
    let best = null, bestDist = Infinity;

    for (const [key, data] of map.entries()) {
      if (!data || !data.group) continue;
      // Ignora recursos em animação de vanish ou invisíveis
      if (!data.group.visible) continue;
      if (data.group.scale.x < 0.1) continue;
      // Filtra por subtipo de pedra se necessário
      if (agIsRockMode() && !agRockMatches(data)) continue;
      const pk = agPrimaryKey(key, data);
      if (seen.has(pk)) continue; seen.add(pk);
      if (agIsRecentlyHarvested(pk)) continue;
      if (agIsBannedSpot(pk)) {
        console.debug(`[AutoGather] agFindNearest: pulando spot banido ${pk}`);
        continue;
      }

      const [tc, tr] = pk.split(',').map(Number);

      // Acha o melhor tile de abordagem para este recurso
      const ap = Ef(tc, tr, blk, ce, de);
      if (!ap) continue; // sem acesso

      // Distância Manhattan do jogador ao tile de abordagem
      const d = Math.abs(ce - ap.col) + Math.abs(de - ap.row);

      // Ignora recursos cujo tile de abordagem é exatamente onde o jogador está
      // ce que o jogador acabou de tentar (evita loop no mesmo recurso preso)
      const apKey = `${ap.col},${ap.row}`;
      if (d === 0 && apKey === agLastApKey && (Date.now() - agLastApKeyAt) < 3000) continue;

      // Modos rock: usa score (cluster + floor + tipo) em vez de só distância
      if (agIsRockMode()) {
        const sc = agRockScore(data, d);
        if (best === null || sc > best._score) {
          best = { col: tc, row: tr, key: pk, ap, apDist: d, _score: sc, _clusterSize: (data.keys||[pk]).length };
        }
      } else if (d < bestDist) {
        bestDist = d;
        best = { col: tc, row: tr, key: pk, ap, apDist: d };
      }
    }

    // Log do spot escolhido no modo rock
    if (agIsRockMode() && best) {
      var _rt = best._score !== undefined
        ? '[rock score=' + (best._score||0).toFixed(3) + ' cluster=' + (best._clusterSize||1) + ']'
        : '[rock dist]';
      AG_LOG.debug('agFindNearest ' + _rt + ' → ' + best.key + ' d=' + best.apDist);
    }

    // Modo tree: escolhe aleatoriamente entre os 3 mais próximos
    // para evitar que múltiplas contas façam exatamente o mesmo percurso
    if (agMode === 'tree' && best) {
      var candidates2 = [];
      var seenC2 = new Set();
      for (var [key2, data2] of map.entries()) {
        if (!data2 || !data2.group || !data2.group.visible || data2.group.scale.x < 0.1) continue;
        var pk2 = agPrimaryKey(key2, data2);
        if (seenC2.has(pk2)) continue; seenC2.add(pk2);
        if (agIsRecentlyHarvested(pk2) || agIsBannedSpot(pk2)) continue;
        var parts2 = pk2.split(',').map(Number);
        var tc2 = parts2[0], tr2 = parts2[1];
        var ap2 = Ef(tc2, tr2, blk, ce, de);
        if (!ap2) continue;
        var d2 = Math.abs(ce - ap2.col) + Math.abs(de - ap2.row);
        candidates2.push({ col: tc2, row: tr2, key: pk2, ap: ap2, apDist: d2, _d: d2 });
      }
      candidates2.sort(function(a, b) { return a._d - b._d; });
      var pool = candidates2.slice(0, 3);
      if (pool.length > 1) {
        var chosen = pool[Math.floor(Math.random() * pool.length)];
        AG_LOG.debug('tree random: ' + pool.map(function(p){return p.key+'(d='+p._d+')';}).join(' | ') + ' → ' + chosen.key);
        return chosen;
      }
    }

    return best;
  }

  // Encontra recurso mais proximo entre arvores e/ou pedras (tree_coal, tree_rock, all)
  // Usa pool top-3 com escolha aleatória para evitar loop no mesmo spot
  
  // Encontra tile de approach para (tc,tr) a partir de (fromCol,fromRow)
  // Retorna {col, row} do tile adjacente mais próximo do jogador que não está bloqueado
  function Ef(tc, tr, blk, fromCol, fromRow) {
    const dirs = [[0,-1],[0,1],[-1,0],[1,0]];
    let best = null, bestD = Infinity;
    for (const [dc, dr] of dirs) {
      const nc = tc + dc, nr = tr + dr;
      if (blk && blk.has(nc + ',' + nr)) continue;
      const d = Math.abs(fromCol - nc) + Math.abs(fromRow - nr);
      if (d < bestD) { bestD = d; best = {col: nc, row: nr}; }
    }
    return best;
  }

  function agFindNearestMulti() {
    const ctx = R3();
    if (!ctx) { AG_LOG.warn('agFindNearestMulti: sem contexto de recursos'); return null; }
    const blk = d();

    const wantTree  = agMode === 'tree_coal' || agMode === 'tree_rock' || agMode === 'all';
    const wantCoal  = agMode === 'tree_coal' || agMode === 'tree_rock' || agMode === 'all';
    const wantStone = agMode === 'tree_rock' || agMode === 'all';
    const wantMetal = agMode === 'all';

    const candidates = [];
    let treeCount = 0, rockCount = 0;

    // Arvores
    if (wantTree && ctx.treeMap) {
      for (const [key, data] of ctx.treeMap.entries()) {
        if (!data || !data.group || !data.group.visible || data.group.scale.x < 0.1) continue;
        if (agIsRecentlyHarvested(key) || agIsBannedSpot(key)) continue;
        const [tc, tr] = key.split(',').map(Number);
        const ap = Ef(tc, tr, blk, ce, de);
        if (!ap) continue;
        const d = Math.abs(ce - ap.col) + Math.abs(de - ap.row);
        const apKey = ap.col + ',' + ap.row;
        if (d === 0 && apKey === agLastApKey && (Date.now() - agLastApKeyAt) < 3000) continue;
        // Search range: ignora recursos além do raio de busca (só no modo OPT)
        if (agOptimizedFarm && agMode === 'all') {
          var _sr = agOptCfg.searchRange || 30;
          if (d > _sr) continue;
        }
        treeCount++;
        candidates.push({ col: tc, row: tr, key, ap, apDist: d, resType: 'tree', _d: d });
      }
    }

    // Pedras (coal, stone, metal conforme modo)
    if ((wantCoal || wantStone || wantMetal) && ctx.rockMap) {
      const seen = new Set();
      for (const [key, data] of ctx.rockMap.entries()) {
        if (!data || !data.group || !data.group.visible || data.group.scale.x < 0.1) continue;
        const pk = (data.keys && data.keys.length > 0) ? data.keys[0] : key;
        if (seen.has(pk)) continue; seen.add(pk);
        if (agIsRecentlyHarvested(pk) || agIsBannedSpot(pk)) continue;
        // Filtra por subtipo
        const hasCoal  = !!data.hasCoal;
        const hasMetal = !!data.hasMetal;
        const hasStone = !hasCoal && !hasMetal; // stone pura
        const wanted   = (wantCoal  && hasCoal)  ||
                         (wantStone && hasStone)  ||
                         (wantMetal && hasMetal)  ||
                         (wantMetal && !hasCoal && !hasMetal); // stone também no all
        if (!wanted) continue;
        const [tc, tr] = pk.split(',').map(Number);
        const ap = Ef(tc, tr, blk, ce, de);
        if (!ap) continue;
        const d = Math.abs(ce - ap.col) + Math.abs(de - ap.row);
        const apKey2 = ap.col + ',' + ap.row;
        if (d === 0 && apKey2 === agLastApKey && (Date.now() - agLastApKeyAt) < 3000) continue;
        // Search range: ignora recursos além do raio de busca (só no modo OPT)
        if (agOptimizedFarm && agMode === 'all') {
          var _sr2 = agOptCfg.searchRange || 30;
          if (d > _sr2) continue;
        }
        rockCount++;
        candidates.push({ col: tc, row: tr, key: pk, ap, apDist: d, resType: 'rock', _d: d });
      }
    }

    // Se não encontrou nada dentro do raio, tenta sem restrição de raio
    if (candidates.length === 0 && agOptimizedFarm && agMode === 'all' && agOptCfg.searchRange) {
      AG_LOG.info('[FarmOpt] Sem recursos no raio ' + agOptCfg.searchRange + ' — expandindo busca...');
      // Refazer coleta sem filtro de raio
      if (wantTree && ctx.treeMap) {
        for (const [key, data] of ctx.treeMap.entries()) {
          if (!data || !data.group || !data.group.visible || data.group.scale.x < 0.1) continue;
          const [tc, tr] = key.split(',').map(Number);
          const ap = Ef(tc, tr, blk);
          if (!ap) continue;
          const d = Math.abs(ce - ap.col) + Math.abs(de - ap.row);
          if (key === agLastApKey && agHarvestDone && agHarvestDone.key === key) continue;
          treeCount++;
          candidates.push({ col: tc, row: tr, key, ap, apDist: d, resType: 'tree', _d: d });
        }
      }
      if ((wantCoal || wantStone || wantMetal) && ctx.rockMap) {
        for (const [key, data] of ctx.rockMap.entries()) {
          if (!data || !data.group || !data.group.visible || data.group.scale.x < 0.1) continue;
          const [rc, rr] = key.split(',').map(Number);
          const ap = Ef(rc, rr, blk);
          if (!ap) continue;
          const d = Math.abs(ce - ap.col) + Math.abs(de - ap.row);
          if (key === agLastApKey && agHarvestDone && agHarvestDone.key === key) continue;
          const hasCoal  = data.hasCoal  ?? (data.type === 'coal');
          const hasMetal = data.hasMetal ?? (data.type === 'metal');
          const isStone  = !hasCoal && !hasMetal;
          if (hasCoal && !wantCoal)   continue;
          if (isStone && !wantStone)  continue;
          if (hasMetal && !wantMetal) continue;
          rockCount++;
          candidates.push({ col: rc, row: rr, key, ap, apDist: d, resType: hasCoal ? 'coal' : hasMetal ? 'metal' : 'stone', _d: d, hasCoal, hasMetal });
        }
      }
      if (candidates.length > 0) {
        AG_LOG.info('[FarmOpt] Encontrou ' + candidates.length + ' recursos fora do raio');
      }
    }

    if (candidates.length === 0) {
      AG_LOG.debug('agFindNearestMulti: nenhum candidato (arvores=' + treeCount + ' pedras=' + rockCount + ')');
      return null;
    }

    var chosen;
    if (agOptimizedFarm && agMode === 'all') {
      // Farm Otimizado: score = (floor × qty_est) / (dist+1) × ruído±20%
      // Determina tipo de recurso por resType + hasCoal/hasMetal
      candidates.forEach(function(cand) {
        var type = cand.resType === 'tree' ? 'wood'
          : (function() {
              // Para pedras, precisa saber o subtipo — tenta via rockMap
              try {
                var ctx = R3();
                var rd = ctx && ctx.rockMap && ctx.rockMap.get(cand.key);
                if (rd && rd.hasMetal) return 'metal';
                if (rd && rd.hasCoal)  return 'coal';
              } catch(_) {}
              return 'stone';
            })();
        var _clSize = (function() { try { var ctx2=R3(); var rd2=ctx2&&ctx2.rockMap&&ctx2.rockMap.get(cand.key); return (rd2&&rd2.keys)?rd2.keys.length:1; } catch(_){return 1;} })();
        cand._score = agOptScore(type, cand._d, _clSize);
        cand._type  = type;
      });

      // Filtra candidatos além do raio (score=-1) e blacklistados
      var optCands = candidates.filter(function(c){ return c._score >= 0; });
      if (!optCands.length) {
        // Fallback: nenhum candidato dentro do raio — pega o mais próximo disponível
        // sem aleatoriedade, para não ir longe demais
        candidates.sort(function(a, b) { return a._d - b._d; });
        chosen = candidates[0];
        AG_LOG.debug('agFindNearestMulti [OPT]: sem candidatos no search range=' + (agOptCfg.searchRange||30) + ' — fallback para mais próximo: ' + (chosen._type||chosen.resType) + '[' + chosen.key + '] d=' + chosen._d);
      } else {
        optCands.sort(function(a, b) { return b._score - a._score; });
        var _pool = Math.min(agOptCfg.poolSize || 3, optCands.length);
        var optPool = optCands.slice(0, Math.max(1, _pool));
        chosen = optPool[Math.floor(Math.random() * optPool.length)];
        AG_LOG.debug('agFindNearestMulti [OPT]: pool=[' +
          optPool.map(function(p){ return p._type + '(d=' + p._d + ' pri=' + (agOptCfg.priority[p._type]||1) + ' score=' + (p._score||0).toFixed(4) + ')'; }).join(', ') +
          '] → ' + chosen._type + '[' + chosen.key + '] score=' + (chosen._score||0).toFixed(4));
      }
    } else {
      // Modo padrão: ordena por distância, top-3 aleatório
      candidates.sort(function(a, b) { return a._d - b._d; });
      var pool = candidates.slice(0, 3);
      chosen = pool[Math.floor(Math.random() * pool.length)];

      AG_LOG.debug('agFindNearestMulti: arvores=' + treeCount + ' pedras=' + rockCount +
        ' | pool=[' + pool.map(function(p){ return p.resType + '(' + p.key + ' d=' + p._d + ')'; }).join(', ') + ']' +
        ' → ' + chosen.resType + '[' + chosen.key + '] d=' + chosen._d);
    }

    return chosen;
  }

  function agGetPortalAvoidSet() {
    const avoid = new Set();
    try {
      if (typeof VE !== 'undefined')
        for (const k of VE) avoid.add(k);
      if (typeof h6 !== 'undefined')
        for (const k of h6) avoid.add(k);
      if (typeof w6 !== 'undefined')
        for (const k of w6) avoid.add(k);
      // Adiciona vizinhos imediatos dos portais para margem de segurança
      const extras = new Set();
      for (const k of avoid) {
        const [c, r] = k.split(',').map(Number);
        extras.add(`${c},${r-1}`);
        extras.add(`${c},${r+1}`);
        extras.add(`${c-1},${r}`);
        extras.add(`${c+1},${r}`);
      }
      for (const k of extras) avoid.add(k);
    } catch (_) {}
    return avoid;
  }

  // Simula click real no canvas para o tile de abordagem do recurso
  function agSimulateClickOnTile(col, row) {
    try {
      // Converte tile col/row para posicao 3D world
      const offX = getActiveOffX ? $e : 0;
      const offZ = getActiveOffZ ? ze : 0;
      const worldX = col + offX;
      const worldZ = row + offZ;
      // Projeta 3D -> NDC -> coordenadas de tela
      const v = new THREE.Vector3(worldX, 0, worldZ);
      v.project(camera);
      const rect = renderer.domElement.getBoundingClientRect();
      const clientX = Math.round(((v.x + 1) / 2) * rect.width  + rect.left);
      const clientY = Math.round(((1 - v.y) / 2) * rect.height + rect.top);
      // Dispara sequencia realista: pointerdown → pointerup → click
      const opts = { bubbles: true, cancelable: true, composed: true, clientX, clientY, pointerId: 1, pointerType: 'mouse', button: 0, buttons: 1 };
      renderer.domElement.dispatchEvent(new PointerEvent('pointerdown', opts));
      setTimeout(() => {
        renderer.domElement.dispatchEvent(new PointerEvent('pointerup', opts));
        renderer.domElement.dispatchEvent(new MouseEvent('click', { ...opts, buttons: 0 }));
      }, 50 + Math.random() * 30);
    } catch(e) { AG_LOG.debug('agSimulateClickOnTile erro: ' + e.message); }
  }

