  function agFindFishTile() {
    const cells = vhe();
    if (!cells || cells.size === 0) return null;
    // uHe = distância máxima (Chebyshev) para pescar — mesmo critério do bundle (bHe)
    var _maxDist = 2; // distância máxima Chebyshev para pesca (configurado)
    // Log de diagnóstico para beach
    AG_LOG.debug('[Fish] vhe cells=' + cells.size + ' playerPos=' + ce + ',' + de + ' maxDist=' + _maxDist + ' realm=' + D);
    let best = null, bestDist = Infinity;
    for (const key of cells) {
      const [c, r] = key.split(',').map(Number);
      const d = Math.max(Math.abs(ce-c), Math.abs(de - r)); // Chebyshev
      AG_LOG.debug('[Fish] tile ' + key + ' d=' + d + ' maxDist=' + _maxDist + ' ok=' + (d <= _maxDist));
      if (d <= _maxDist && d < bestDist) { bestDist = d; best = { col: c, row: r }; }
    }
    AG_LOG.debug('[Fish] best=' + JSON.stringify(best));
    return best;
  }

  function agFindFishingSpot() {
    const cells = vhe();
    if (!cells || cells.size === 0) {
      AG_LOG.debug('[Fish] agFindFishingSpot: vhe vazio para realm=' + D);
      return null;
    }
    const blk = d();
    var _maxDist = 2; // distância máxima Chebyshev para pesca (configurado)
    AG_LOG.debug('[Fish] agFindFishingSpot: cells=' + cells.size + ' maxDist=' + _maxDist);
    let best = null, bestDist = Infinity;
    // Busca tiles terrestres dentro de uHe tiles de qualquer tile de água
    for (const key of cells) {
      const [wc, wr] = key.split(',').map(Number);
      // Buscar tiles não-bloqueados dentro de uHe (Chebyshev) do tile de água
      for (let dc = -_maxDist; dc <= _maxDist; dc++) {
        for (let dr = -_maxDist; dr <= _maxDist; dr++) {
          if (!dc && !dr) continue;
          if (Math.max(Math.abs(dc), Math.abs(dr)) > _maxDist) continue;
          const lc = wc+dc, lr = wr+dr;
          if (cells.has(lc+','+lr)) continue; // é tile de água — não pode estar lá
          if (blk.has(lc+','+lr)) continue;   // bloqueado
          const d = Math.max(Math.abs(ce-lc), Math.abs(de-lr));
          if (d < bestDist) { bestDist = d; best = { col: lc, row: lr }; }
        }
      }
    }
    AG_LOG.debug('[Fish] agFindFishingSpot: best=' + JSON.stringify(best) + ' dist=' + bestDist);
    return best;
  }

