  // ── Map Info mini HUD ──────────────────────────────────────────────────────
  function agOpenMapInfoHud() {
    const existing = document.getElementById('ag-mapinfo-host');
    if (existing) { existing.remove(); return; }

    const host = document.createElement('div');
    host.id = 'ag-mapinfo-host';
    var _miPos = (function(){ try{ return JSON.parse(localStorage.getItem('kintara_ag_mapinfo_pos'))||{}; }catch(_){ return {}; } })();
    Object.assign(host.style, {
      position:'fixed', zIndex:'2147483647', pointerEvents:'none',
      top: _miPos.top || '120px', left: _miPos.left || '200px', right: _miPos.right || 'auto',
    });
    document.body.appendChild(host);
    const shadow = host.attachShadow({ mode:'open' });

    const styleEl = document.createElement('style');
    styleEl.textContent = `
      :host{all:initial}
      #mi-panel{
        pointer-events:auto;
        background:rgba(10,12,20,0.94);border:1px solid rgba(255,255,255,0.13);
        border-radius:8px;padding:8px 10px;min-width:170px;
        font-family:'Segoe UI',system-ui,sans-serif;font-size:11px;color:#d4d8e2;
        box-shadow:0 4px 20px rgba(0,0,0,0.6);user-select:none;
      }
      #mi-header{display:flex;align-items:center;justify-content:space-between;margin-bottom:6px;cursor:grab}
      #mi-header:active{cursor:grabbing}
      #mi-title{font-size:9px;font-weight:700;text-transform:uppercase;letter-spacing:.08em;color:#7eb8f7}
      #mi-realm{font-size:9px;color:#556;margin-left:4px}
      #mi-close{background:none;border:none;color:#556;font-size:12px;cursor:pointer;padding:0;line-height:1}
      #mi-close:hover{color:#aab}
      .mi-section{font-size:8px;font-weight:700;text-transform:uppercase;letter-spacing:.06em;color:#445;margin:5px 0 3px}
      .mi-row{display:flex;justify-content:space-between;align-items:center;padding:2px 0;border-bottom:1px solid rgba(255,255,255,0.04)}
      .mi-row:last-child{border-bottom:none}
      .mi-name{color:#a0aab8;font-size:11px;display:flex;align-items:center;gap:4px}
      .mi-qty{color:#d4d8e2;font-weight:700;font-variant-numeric:tabular-nums}
      .mi-qty.green{color:#6ee7a0}
      .mi-qty.orange{color:#f97316}
      .mi-empty{color:#445;font-style:italic;font-size:10px;padding:2px 0}
    `;

    const panel = document.createElement('div');
    panel.id = 'mi-panel';
    panel.innerHTML =
      '<div id="mi-header">' +
        '<span><span id="mi-title">MAPA</span><span id="mi-realm"></span></span>' +
        '<button id="mi-close">&#10005;</button>' +
      '</div>' +
      '<div id="mi-content"><div class="mi-empty">Carregando...</div></div>';

    shadow.appendChild(styleEl);
    shadow.appendChild(panel);

    const $m = (id) => shadow.getElementById(id);
    var _miPrevHud = _agCh;
    $m('mi-close').addEventListener('click', function() {
      _agCh = _miPrevHud;
      host.remove();
      agSaveHudState();
    });

    // Drag
    var drag = null;
    $m('mi-header').addEventListener('pointerdown', function(e) {
      e.stopPropagation();
      var r = host.getBoundingClientRect();
      drag = { dx: e.clientX - r.left, dy: e.clientY - r.top };
      $m('mi-header').setPointerCapture(e.pointerId);
    });
    $m('mi-header').addEventListener('pointermove', function(e) {
      if (!drag) return;
      e.stopPropagation();
      host.style.left = (e.clientX - drag.dx) + 'px';
      host.style.top  = (e.clientY - drag.dy) + 'px';
    });
    $m('mi-header').addEventListener('pointerup', function(e) { e.stopPropagation(); drag = null; try{localStorage.setItem('kintara_ag_mapinfo_pos',JSON.stringify({left:host.style.left,top:host.style.top,right:host.style.right}));}catch(_){} agSaveHudState(); });

    // HUD patch
    var _orig3 = _agCh;
    _agCh = function(node) {
      if (_orig3(node)) return true;
      var path = node && node.composedPath ? node.composedPath() : [];
      return path.includes(host) || host.contains(node);
    };

    function img(src, size) {
      return '<img src="' + src + '" width="' + (size||14) + '" height="' + (size||14) + '" style="vertical-align:middle;image-rendering:pixelated" draggable="false">';
    }

    // Track max seen (updates up if new resources spawn)
    var miMaxTree=0, miMaxStone=0, miMaxCoal=0;
    var miLastRealm = '';

    function renderMapInfo() {
      try {
        const realmEl = $m('mi-realm');
        if (realmEl) realmEl.textContent = ' — ' + (m || '?');

        // Reset maxes on realm change
        if (m !== miLastRealm) {
          miMaxTree=0; miMaxStone=0; miMaxCoal=0;
          miLastRealm = m || '';
        }

        const el = $m('mi-content');
        if (!el) return;
        var html = '';

        // Resources
        const ctx = R3();
        if (ctx) {
          var treeAlive = 0;
          if (ctx.treeMap) {
            for (const [, data] of ctx.treeMap.entries()) {
              if (data && data.group && data.group.visible && data.group.scale.x > 0.1) treeAlive++;
            }
          }
          if (treeAlive > miMaxTree) miMaxTree = treeAlive;

          var stoneAlive=0, coalAlive=0;
          if (ctx.rockMap) {
            const seen = new Set();
            for (const [key, data] of ctx.rockMap.entries()) {
              const pk = (data && data.keys && data.keys.length > 0) ? data.keys[0] : key;
              if (seen.has(pk)) continue; seen.add(pk);
              const alive = data && data.group && data.group.visible && data.group.scale.x > 0.1;
              if (!alive) continue;
              if (data && data.hasCoal) coalAlive++;
              else stoneAlive++;
            }
          }
          if (stoneAlive > miMaxStone) miMaxStone = stoneAlive;
          if (coalAlive  > miMaxCoal)  miMaxCoal  = coalAlive;

          if (miMaxTree > 0 || miMaxStone > 0 || miMaxCoal > 0) {
            html += '<div class="mi-section">Recursos</div>';
            if (miMaxTree  > 0) html += '<div class="mi-row"><span class="mi-name">' + img('/assets/hud/resources/wood.png') + ' Madeira</span><span class="mi-qty' + (treeAlive  < miMaxTree  * 0.3 ? ' orange' : ' green') + '">' + treeAlive  + '/' + miMaxTree  + '</span></div>';
            if (miMaxStone > 0) html += '<div class="mi-row"><span class="mi-name">' + img('/assets/hud/resources/stone.png') + ' Stone</span><span class="mi-qty'  + (stoneAlive < miMaxStone * 0.3 ? ' orange' : ' green') + '">' + stoneAlive + '/' + miMaxStone + '</span></div>';
            if (miMaxCoal  > 0) html += '<div class="mi-row"><span class="mi-name">' + img('/assets/hud/resources/coal.png') + ' Coal</span><span class="mi-qty'   + (coalAlive  < miMaxCoal  * 0.3 ? ' orange' : ' green') + '">' + coalAlive  + '/' + miMaxCoal  + '</span></div>';
          }
        }

        // Mobs
        var mobHtml = '';
        // Chickens (eldergrove)
        if (D==='eldergrove' && typeof lr !== 'undefined') {
          try {
            var chickenAlive = 0, chickenTotal = 0;
            for (var ci = 0; ci < 30; ci++) {
              const foot = lr.getChickenApproximateFoot(ci);
              if (foot !== null && foot !== undefined) { chickenTotal++; chickenAlive++; }
            }
            if (chickenTotal > 0) mobHtml += '<div class="mi-row"><span class="mi-name">' + img('/assets/hud/resources/rawchicken.png') + ' Galinhas</span><span class="mi-qty green">' + chickenAlive + '</span></div>';
          } catch(_) {}
        }
        // Wild zombies
        if ((D==='wild' || D==='wild_exp' || D==='wild_ext' || D==='ember') && typeof _agChopState !== 'undefined') {
          try {
            const sys = hr();
            if (sys) {
              var zombieAlive = 0;
              for (var zi = 0; zi < 20; zi++) {
                const foot = sys.getEnemyApproximateFoot(zi);
                if (foot !== null && foot !== undefined) zombieAlive++;
              }
              if (zombieAlive > 0) mobHtml += '<div class="mi-row"><span class="mi-name"><span style="display:inline-block;width:14px;height:14px;background:#c0392b;border-radius:2px;text-align:center;line-height:14px;font-size:8px;font-weight:800;color:#fff">Z</span> Zombies</span><span class="mi-qty orange">' + zombieAlive + '</span></div>';
            }
          } catch(_) {}
        }

        if (mobHtml) html += '<div class="mi-section">Mobs</div>' + mobHtml;

        // Players no mapa
        try {
          var playerCount = agGetMapPlayerCount();
          if (playerCount < 0) playerCount = 0;
          var playersHtml = '<div class="mi-section">Players</div>' +
            '<div class="mi-row"><span class="mi-name">👥 No mapa</span><span class="mi-qty green">' + playerCount + '</span></div>';
          html += playersHtml;
        } catch(_) {}

        if (!html) html = '<div class="mi-empty">Nada encontrado neste mapa</div>';
        el.innerHTML = html;
      } catch(e) {
        console.error('[MapHUD] Erro:', e.message, e.stack && e.stack.split('\n')[1]);
        const el = $m('mi-content');
        if (el) el.innerHTML = '<div class="mi-empty">Erro ao ler mapa: ' + e.message + '</div>';
      }
    }

    renderMapInfo();
    var miTimer = setInterval(function() {
      if (!document.getElementById('ag-mapinfo-host')) { clearInterval(miTimer); return; }
      renderMapInfo();
    }, 2000);
  }


