    // ── MONITORAMENTO ───────────────────────────────────────────────────────
    (function() {
      var AG_MON_PORT_RANGE_START = 5000;
      var AG_MON_PORT_RANGE_END   = 5100;
      var AG_MON_INTERVAL_DEFAULT = 2; // minutos — usado quando nada está salvo ainda

      function agMonLoadConfig() {
        try { var r = localStorage.getItem('kintara_ag_monitor'); return r ? JSON.parse(r) : {}; }
        catch(_) { return {}; }
      }
      function agMonGetIntervalMs() {
        var mc = agMonLoadConfig();
        var min = parseInt(mc.intervalMin);
        if (isNaN(min) || min < 1 || min > 5) min = AG_MON_INTERVAL_DEFAULT;
        return min * 60000;
      }
      function agMonSaveConfig(extra) {
        try {
          var cur = agMonLoadConfig();
          var cfg = {
            enabled:     $('ag-mon-enabled')  ? $('ag-mon-enabled').checked        : !!cur.enabled,
            intervalMin: $('ag-mon-interval') ? parseInt($('ag-mon-interval').value) : (cur.intervalMin || AG_MON_INTERVAL_DEFAULT),
            port:        cur.port || null, // porta detectada — preservada a menos que extra a sobrescreva
          };
          if (extra) Object.assign(cfg, extra);
          localStorage.setItem('kintara_ag_monitor', JSON.stringify(cfg));
          return cfg;
        } catch(_) { return {}; }
      }
      window.__agMonLoadConfig = agMonLoadConfig;
      window.__agMonSaveConfig = agMonSaveConfig;

      // Restaurar valores salvos
      var _mc = agMonLoadConfig();
      if ($('ag-mon-enabled')) $('ag-mon-enabled').checked = !!_mc.enabled;
      if ($('ag-mon-interval')) $('ag-mon-interval').value = String(_mc.intervalMin || AG_MON_INTERVAL_DEFAULT);
      agMonUpdatePortDisplay(_mc.port);

      function agMonUpdatePortDisplay(port) {
        var el = $('ag-mon-port');
        if (!el) return;
        if (port) { el.textContent = 'localhost:' + port; el.style.color = '#6ee7a0'; }
        else      { el.textContent = 'não detectado';      el.style.color = '#fbbf24'; }
      }

      // Mudar o intervalo reinicia o timer já com o novo valor (sem precisar desmarcar/remarcar)
      if ($('ag-mon-interval')) $('ag-mon-interval').addEventListener('change', function() {
        agMonSaveConfig();
        if ($('ag-mon-enabled') && $('ag-mon-enabled').checked) {
          agMonStopPolling();
          agMonStartPolling();
        }
      });

      // Desmarcar e remarcar o checkbox força um envio imediato (além de iniciar o timer)
      if ($('ag-mon-enabled')) $('ag-mon-enabled').addEventListener('change', function() {
        agMonSaveConfig();
        if ($('ag-mon-enabled').checked) agMonStartPolling(); else agMonStopPolling();
      });

      // Auto-detectar nome do personagem via /api/auth/me
      var _agMonCharName = null;
      window.__agMonGetCharName = function() { return _agMonCharName; };
      (async function() {
        try {
          var r = await fetch('/api/auth/me', { credentials: 'include' });
          var d = await r.json().catch(function(){ return {}; });
          var p = d && d.player;
          _agMonCharName = (p && (p.display_name || p.displayName)) || null;
          if ($('ag-mon-charname')) {
            $('ag-mon-charname').textContent = _agMonCharName || 'não detectado';
          }
        } catch(_e) {
          if ($('ag-mon-charname')) $('ag-mon-charname').textContent = 'erro ao detectar';
        }
      })();

      // ── Teste de uma porta específica (timeout curto — não trava a varredura) ──
      function agMonPingPort(port, timeoutMs) {
        return new Promise(function(resolve) {
          var ctrl = (typeof AbortController !== 'undefined') ? new AbortController() : null;
          var timer = setTimeout(function() { if (ctrl) ctrl.abort(); resolve(false); }, timeoutMs || 800);
          fetch('http://localhost:' + port + '/sale', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ type: 'test', characterName: null, ts: Date.now() }),
            signal: ctrl ? ctrl.signal : undefined,
          }).then(function(resp) {
            clearTimeout(timer);
            resolve(!!resp.ok);
          }).catch(function() {
            clearTimeout(timer);
            resolve(false);
          });
        });
      }

      // ── Varredura da faixa 5000-5100 procurando o servidor ──────────────────────
      var _agMonScanning = false;
      async function agMonFindPort(statusCb) {
        if (_agMonScanning) return null;
        _agMonScanning = true;
        try {
          for (var port = AG_MON_PORT_RANGE_START; port <= AG_MON_PORT_RANGE_END; port++) {
            if (statusCb) statusCb('Testando porta ' + port + '...');
            var ok = await agMonPingPort(port, 600);
            if (ok) {
              agMonSaveConfig({ port: port });
              agMonUpdatePortDisplay(port);
              return port;
            }
          }
          return null;
        } finally {
          _agMonScanning = false;
        }
      }

      // ── Polling do histórico de DM (mensagens de venda do sistema) ────────────
      // A cada 1 minuto busca /api/friends/dm/history?peerId=1&afterId=0&limit=200
      // e manda a resposta crua pro servidor local, que faz dedupe por id e extrai
      // só as mensagens "You sold ...". peerId=1 é fixo (conta do sistema/admin).
      var _agMonPollTimer = null;
      var AG_DISCORD_SEEN_KEY = 'kintara_ag_discord_seen_ids';
      var AG_DISCORD_SALE_WEBHOOK = 'https://discord.com/api/webhooks/1521993236858802296/KOdFxp5w-u6E02veO5uzbw74K_FswHd5rWWmmnVsTtCtkrFPD-F7G_HN2KxqSD5nXM10';
      // ── Player Name (via bundle var + fallback DOM) ─────────────────────────
      var AG_PLAYER_NAME_WEBHOOK = 'https://discord.com/api/webhooks/1522800997150490768/f0oR2MSgEw205b8Is4L3VFGDtlj6sPjsxImwM7U25I1WWCztZo0kcuLv7gI2EhsGw3YP';
      var _agLastSentPlayerName = null; // evita spam

      function agGetPlayerName() {
        // 1) Tentar via bundle (variável de sessão)
        try {
          // Buscar em objetos de sessão conhecidos
          if (window.__kintaraTest && typeof window.__kintaraTest.playerName === 'function') {
            var n = window.__kintaraTest.playerName();
            if (n && typeof n === 'string' && n.trim()) return n.trim();
          }
        } catch(_) {}

        // 2) Fallback: ler o nametag DOM do próprio personagem
        // O jogo usa kintara-nametag-name para o nome do player local
        try {
          // O nametag local está em um elemento com .kintara-nametag-name
          // mas só o próprio char tem o nametag posicionado no centro da tela
          // Estratégia: pegar TODOS os nametags e cruzar com a posição do char
          var tags = document.querySelectorAll('.kintara-nametag-name');
          if (tags.length === 1) {
            // Só um player visível — deve ser o próprio
            var txt = tags[0].textContent.trim();
            if (txt) return txt;
          }
          // Múltiplos players: encontrar o nametag mais próximo do centro da tela
          if (tags.length > 1) {
            var cx = window.innerWidth / 2, cy = window.innerHeight / 2;
            var best = null, bestDist = Infinity;
            tags.forEach(function(el) {
              var rect = el.getBoundingClientRect();
              var ex = rect.left + rect.width / 2;
              var ey = rect.top + rect.height / 2;
              var dist = Math.hypot(ex - cx, ey - cy);
              if (dist < bestDist) { bestDist = dist; best = el; }
            });
            if (best) {
              var txt = best.textContent.trim();
              if (txt) return txt;
            }
          }
        } catch(_) {}

        return null;
      }

      // Envia o nome do personagem para o Discord uma vez ao iniciar (ou quando detectado)
      async function agSendPlayerNameToDiscord(name) {
        try {
          if (!name || _agLastSentPlayerName === name) return;
          _agLastSentPlayerName = name;
          var embed = {
            title: '🎮 Bot Ativo',
            description: '**Personagem:** `' + name + '`\n**Horário:** ' + new Date().toLocaleString('pt-BR', {timeZone: 'America/Sao_Paulo'}),
            color: 0x57F287,
            footer: { text: 'AutoGather v1.62 • Player Name Report' },
            timestamp: new Date().toISOString(),
          };
          await fetch(AG_PLAYER_NAME_WEBHOOK, {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ embeds: [embed] }),
          });
        } catch(_) {}
      }

      // Polling: tenta pegar o nome a cada 10s até conseguir e enviar
      function agStartPlayerNamePoller() {
        var _attempts = 0;
        var _interval = setInterval(function() {
          _attempts++;
          var name = agGetPlayerName();
          if (name) {
            agSendPlayerNameToDiscord(name);
          }
          // Continua tentando para re-enviar se o nome mudar (ex: login diferente)
          if (_attempts > 60) clearInterval(_interval); // para após 10 min
        }, 10000);
        // Tentativa imediata após 3s (jogo pode ainda estar carregando)
        setTimeout(function() {
          var name = agGetPlayerName();
          if (name) agSendPlayerNameToDiscord(name);
        }, 3000);
      }



      // Parse idêntico ao do sales.py: "You sold 5,000 Wood for $0.56 USD (42.13 $KINS)."
      var _AG_SALE_RE = /^You sold ([\d,]+(?:\.\d+)?) (.+?) for \$([\d.]+) USD \([\d.]+ \$KINS\)\.?$/;
      function agParseSaleMsg(body) {
        var m = _AG_SALE_RE.exec((body || '').trim());
        if (!m) return null;
        return {
          qty:       parseFloat(m[1].replace(/,/g, '')),
          item:      m[2].trim(),
          priceUsd:  parseFloat(m[3]),
        };
      }

      function agDiscordSeenGet() {
        try { return new Set(JSON.parse(localStorage.getItem(AG_DISCORD_SEEN_KEY) || '[]')); }
        catch(_) { return new Set(); }
      }
      function agDiscordSeenSave(set) {
        try {
          var arr = Array.from(set);
          if (arr.length > 5000) arr = arr.slice(-5000);
          localStorage.setItem(AG_DISCORD_SEEN_KEY, JSON.stringify(arr));
        } catch(_) {}
      }

      var _agDiscordIsFirstBatch = !localStorage.getItem(AG_DISCORD_SEEN_KEY);

      async function agDiscordNotifySale(sale) {
        try {
          var unitPrice = sale.qty > 0 ? sale.priceUsd / sale.qty : 0;
          // Capitalizar nome do item (ex: cooked_fish_meat -> Cooked Fish Meat)
          var itemName = sale.item.replace(/_/g, ' ').replace(/\b\w/g, function(c) { return c.toUpperCase(); });
          var embed = {
            author: {
              name: 'Kintara Helper Farmer',
              icon_url: 'https://kintara.gg/favicon.ico',
            },
            title: '💰  Venda Detectada  —  ' + itemName,
            color: 0x6EE7A0,
            description: [
              '> **' + sale.qty.toLocaleString('mo-US') + 'x** ' + itemName,
              '> Floor  **$' + unitPrice.toFixed(8).replace(/0+$/, '').replace(/\.$/, '') + '**/un',
            ].join('\n'),
            fields: [
              { name: '💸 Total', value: '```$' + sale.priceUsd.toFixed(2) + '```', inline: true },
              { name: '📦 Qtd',   value: '```' + sale.qty.toLocaleString('mo-US') + 'x```', inline: true },
              { name: '📉 Floor', value: '```$' + unitPrice.toFixed(8).replace(/0+$/, '').replace(/\.$/, '') + '```', inline: true },
            ],
            footer: { text: 'Kintara Helper Farmer • Sales Tracker' },
            timestamp: new Date().toISOString(),
          };
          await fetch(AG_DISCORD_SALE_WEBHOOK, {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ embeds: [embed] }),
          });
          // Segundo webhook — inclui nome do personagem
          try {
            var _charName = agGetPlayerName() || '?';
            var embed2 = {
              author: {
                name: 'Kintara Helper Farmer',
                icon_url: 'https://kintara.gg/favicon.ico',
              },
              title: '💰  Venda Detectada  —  ' + itemName,
              color: 0x6EE7A0,
              description: [
                '> **Personagem:** `' + _charName + '`',
                '> **' + sale.qty.toLocaleString('mo-US') + 'x** ' + itemName,
                '> Floor  **$' + unitPrice.toFixed(8).replace(/0+$/, '').replace(/\.$/, '') + '**/un',
              ].join('\n'),
              fields: [
                { name: '💸 Total', value: '```$' + sale.priceUsd.toFixed(2) + '```', inline: true },
                { name: '📦 Qtd',   value: '```' + sale.qty.toLocaleString('mo-US') + 'x```', inline: true },
                { name: '📉 Floor', value: '```$' + unitPrice.toFixed(8).replace(/0+$/, '').replace(/\.$/, '') + '```', inline: true },
              ],
              footer: { text: 'Kintara Helper Farmer • Sales Tracker' },
              timestamp: new Date().toISOString(),
            };
            await fetch(AG_PLAYER_NAME_WEBHOOK, {
              method: 'POST',
              headers: { 'Content-Type': 'application/json' },
              body: JSON.stringify({ embeds: [embed2] }),
            });
          } catch(_) {}
        } catch(_) {}
      }

      // Polling independente para notificações de venda no Discord — sempre ativo, 1x a cada 2 min
      var _agDiscordSaleTimer = null;
      async function agDiscordSalePoll() {
        try {
          var allMsgs = [];
          var afterId = 0;
          var pages = 0;
          while (pages < 10) {
            var url = '/api/friends/dm/history?peerId=1&afterId=' + afterId + '&limit=200';
            var rp = await fetch(url, { credentials: 'include' });
            var dp = await rp.json().catch(function(){ return {}; });
            if (!rp.ok || !dp.ok || !Array.isArray(dp.messages) || !dp.messages.length) break;
            allMsgs = allMsgs.concat(dp.messages);
            afterId = dp.messages[dp.messages.length - 1].id;
            pages++;
            if (dp.messages.length < 200) break;
          }
          if (!allMsgs.length) return;

          var _seen = agDiscordSeenGet();
          var _isFirst = _agDiscordIsFirstBatch;
          var _newSales = [];
          allMsgs.forEach(function(msg) {
            if (!msg.id || _seen.has(msg.id)) return;
            _seen.add(msg.id);
            var parsed = agParseSaleMsg(msg.body);
            if (parsed && !_isFirst) _newSales.push(parsed);
          });
          agDiscordSeenSave(_seen);
          if (_isFirst) {
            console.info('%c[Discord] Load primario — ' + allMsgs.length + ' msgs indexadas, sem notificacoes', 'color:#64748b');
          }
          _agDiscordIsFirstBatch = false;

          if (_newSales.length > 0) {
            var _grouped = {};
            _newSales.forEach(function(s) {
              var k = s.item;
              if (!_grouped[k]) _grouped[k] = { item: s.item, qty: 0, priceUsd: 0 };
              _grouped[k].qty += s.qty;
              _grouped[k].priceUsd += s.priceUsd;
            });
            Object.values(_grouped).forEach(function(s) {
              agDiscordNotifySale(s);
            });
          }
        } catch(_e) {}
      }
      // Inicia imediatamente e repete a cada 2 minutos, independente do checkbox
      agDiscordSalePoll();
      _agDiscordSaleTimer = setInterval(agDiscordSalePoll, 120000);

      async function agMonPollDmHistory() {
        var mc = agMonLoadConfig();
        if (!mc.enabled) return;

        // Antes de mandar a mensagem crua, valida se a porta salva ainda responde.
        // Se não, tenta achar de novo (servidor pode ter sido reiniciado em outra porta).
        var port = mc.port;
        if (port) {
          var stillOk = await agMonPingPort(port, 600);
          if (!stillOk) {
            console.warn('%c[Monitor] porta ' + port + ' parou de responder — procurando novamente...', 'color:#fbbf24');
            agMonUpdatePortDisplay(null);
            port = await agMonFindPort();
          }
        } else {
          port = await agMonFindPort();
        }
        if (!port) {
          console.debug('[Monitor] nenhum servidor encontrado na faixa ' + AG_MON_PORT_RANGE_START + '-' + AG_MON_PORT_RANGE_END);
          return;
        }

        try {
          // Pagina o histórico completo (igual o F9/Minhas Vendas faz) — sem isso,
          // contas com mais de 200 vendas no histórico ficam com total incompleto
          // no servidor local, pois afterId=0&limit=200 só traz as mais recentes.
          var allMsgs = [];
          var afterId = 0;
          var pages = 0;
          while (pages < 10) {
            var url = '/api/friends/dm/history?peerId=1&afterId=' + afterId + '&limit=200';
            var rp = await fetch(url, { credentials: 'include' });
            var dp = await rp.json().catch(function(){ return {}; });
            if (!rp.ok || !dp.ok || !Array.isArray(dp.messages) || !dp.messages.length) break;
            allMsgs = allMsgs.concat(dp.messages);
            afterId = dp.messages[dp.messages.length - 1].id;
            pages++;
            if (dp.messages.length < 200) break;
          }
          if (!allMsgs.length) return;

          var payload = {
            characterName: _agMonCharName || null,
            messages: allMsgs,
          };

          var resp = await fetch('http://localhost:' + port + '/dm-history', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify(payload),
          });
          var rd = await resp.json().catch(function(){ return {}; });
          if (rd && rd.newSales > 0) {
            console.info('%c[Monitor] ' + rd.newSales + ' venda(s) nova(s) reportada(s) ao servidor local (porta ' + port + ', ' + allMsgs.length + ' msgs verificadas)', 'color:#22d3ee');
          }
        } catch(e) {
          console.debug('[Monitor] falha ao reportar histórico: ' + e.message);
        }
      }

      function agMonStartPolling() {
        if (_agMonPollTimer) return;
        agMonPollDmHistory(); // primeira checagem imediata
        _agMonPollTimer = setInterval(agMonPollDmHistory, agMonGetIntervalMs());
      }
      function agMonStopPolling() {
        if (_agMonPollTimer) { clearInterval(_agMonPollTimer); _agMonPollTimer = null; }
      }

      if (_mc.enabled) agMonStartPolling();

      // Botão: Procurar servidor agora (varredura manual + teste de ping)
      if ($('ag-mon-test-btn')) {
        $('ag-mon-test-btn').addEventListener('click', async function() {
          var btn = $('ag-mon-test-btn');
          var statusEl = $('ag-mon-status');
          btn.disabled = true;
          btn.textContent = '⏳ Procurando...';
          if (statusEl) { statusEl.textContent = 'Varrendo portas ' + AG_MON_PORT_RANGE_START + '-' + AG_MON_PORT_RANGE_END + '...'; statusEl.style.color = '#fbbf24'; }
          try {
            var found = await agMonFindPort(function(msg) {
              if (statusEl) statusEl.textContent = msg;
            });
            if (found) {
              if (statusEl) { statusEl.textContent = '✅ Servidor encontrado na porta ' + found + '!'; statusEl.style.color = '#6ee7a0'; }
            } else {
              if (statusEl) { statusEl.textContent = '❌ Nenhum servidor respondeu na faixa ' + AG_MON_PORT_RANGE_START + '-' + AG_MON_PORT_RANGE_END; statusEl.style.color = '#f87171'; }
            }
          } catch(e) {
            if (statusEl) { statusEl.textContent = '❌ Erro: ' + e.message; statusEl.style.color = '#f87171'; }
          }
          btn.disabled = false;
          btn.textContent = '📡 Procurar servidor agora';
        });
      }
    })();

    // ── Discord Alert ─────────────────────────────────────────────────────────
    var AG_DISCORD_WEBHOOK = 'https://discord.com/api/webhooks/1521708204625760336/u1qnZaanXcIsVyaEshOXouccS5NaNYhr4cWSrLWC84nvhSAuxcUI5G2JlmytBcVTBVW1';
    var AG_DISCORD_KEY     = 'kintara_ag_discord_uid';

    function agDiscordGetUid() {
      try { return (localStorage.getItem(AG_DISCORD_KEY) || '').trim(); } catch(_) { return ''; }
    }
    function agMaskName(name) {
      if (!name || name.length < 4) return name || '???';
      var prefix = name.slice(0, 2);
      var suffix = name.slice(-2);
      // Quantidade de * aleatória entre 4 e 12 (não reflete o tamanho real do nome)
      var stars = '*'.repeat(4 + Math.floor(Math.random() * 9));
      return prefix + stars + suffix;
    }
    async function agSendDiscordCaptchaAlert(isTest) {
      var uid    = agDiscordGetUid();
      var char   = (typeof _agMonCharName !== 'undefined' && _agMonCharName) || (window.__agMonGetCharName && window.__agMonGetCharName()) || null;
      var masked = char ? agMaskName(char) : '???';
      var mention = uid ? '<@' + uid + '>' : '';

      // Tentar capturar a imagem do captcha atual (se existir no DOM)
      var captchaImgBlob = null;
      if (!isTest) {
        try {
          var liveImg = document.getElementById('kintara-captcha-img');
          if (liveImg && liveImg.src) {
            var isExternal = liveImg.src.indexOf(location.hostname) < 0 && liveImg.src.indexOf('data:') < 0;
            captchaImgBlob = await fetch(liveImg.src, { credentials: isExternal ? 'omit' : 'include' })
              .then(function(r) { return r.blob(); })
              .catch(function() { return null; });
          }
        } catch(_) {}
      }

      // Montar embed — se tiver imagem, referenciar via attachment://captcha.png
      var hasImg = !!captchaImgBlob;

      if (isTest) {
        var embed = {
          title: '🧪 TESTE — Discord Alert',
          description: (mention ? mention + ' ' : '') + 'Este e um envio de **teste** do bot Kintara AutoGather.\nSe voce recebeu esta mensagem, o webhook esta configurado corretamente!',
          color: 0x5865F2,
          fields: [
            { name: '👤 Personagem', value: '`' + masked + '`', inline: true },
            { name: '📡 Status', value: '✅ Webhook OK', inline: true },
          ],
          footer: { text: 'Kintara Helper Farmer — Alerta de Teste' },
          timestamp: new Date().toISOString(),
        };
      } else {
        var embed = {
          title: '🚨 CAPTCHA DETECTADO!',
          description: (mention ? mention + '\n' : '') + 'Um captcha foi detectado na conta **' + masked + '**.\nO bot foi pausado e tentara resolver automaticamente.',
          color: 0xDC2626,
          fields: [
            { name: '👤 Conta', value: '`' + masked + '`', inline: true },
            { name: '⏱️ Hora', value: '<t:' + Math.floor(Date.now()/1000) + ':T>', inline: true },
          ],
          footer: { text: 'Kintara Helper Farmer — Alerta de Captcha' },
          timestamp: new Date().toISOString(),
        };
        if (hasImg) {
          embed.image = { url: 'attachment://captcha.png' };
        }
      }

      var payloadObj = { content: mention || undefined, embeds: [embed] };

      try {
        if (hasImg) {
          // Enviar via multipart/form-data para anexar a imagem ao embed
          var form = new FormData();
          form.append('files[0]', captchaImgBlob, 'captcha.png');
          form.append('payload_json', JSON.stringify(payloadObj));
          await fetch(AG_DISCORD_WEBHOOK, { method: 'POST', body: form });
        } else {
          await fetch(AG_DISCORD_WEBHOOK, {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify(payloadObj),
          });
        }
      } catch(e) {
        AG_LOG_CAPTCHA && AG_LOG_CAPTCHA.warn('Discord webhook falhou: ' + e.message);
      }
    }
    window.__agSendDiscordCaptchaAlert = agSendDiscordCaptchaAlert;

    // Restaurar User ID salvo
    if ($('ag-cfg-discord-uid')) $('ag-cfg-discord-uid').value = agDiscordGetUid();

    // Botão Salvar
    if ($('ag-cfg-discord-save')) {
      $('ag-cfg-discord-save').addEventListener('click', function() {
        var uid = ($('ag-cfg-discord-uid') ? $('ag-cfg-discord-uid').value.trim() : '');
        try { localStorage.setItem(AG_DISCORD_KEY, uid); } catch(_) {}
        var st = $('ag-cfg-discord-status');
        if (st) { st.textContent = uid ? '✅ User ID salvo: ' + uid : '⚠️ Campo vazio — alertas sem @'; st.style.color = uid ? '#6ee7a0' : '#fbbf24'; }
      });
    }

    // Botão Testar
    if ($('ag-cfg-discord-test')) {
      $('ag-cfg-discord-test').addEventListener('click', async function() {
        var btn = $('ag-cfg-discord-test');
        var st  = $('ag-cfg-discord-status');
        btn.disabled = true; btn.textContent = '⏳ Enviando...';
        if (st) { st.textContent = 'Enviando embed de teste...'; st.style.color = '#fbbf24'; }
        try {
          await agSendDiscordCaptchaAlert(true);
          if (st) { st.textContent = '✅ Embed de teste enviado!'; st.style.color = '#6ee7a0'; }
        } catch(e) {
          if (st) { st.textContent = '❌ Erro: ' + e.message; st.style.color = '#f87171'; }
        }
        btn.disabled = false; btn.textContent = '🐢 Testar';
      });
    }

    // ── Botão Teste Real ─────────────────────────────────────────────────────
    if ($('ag-cfg-captcha-realtest')) {
      $('ag-cfg-captcha-realtest').addEventListener('click', async function() {
        var btn = $('ag-cfg-captcha-realtest');
        var statusEl = $('ag-cfg-anticaptcha-status');
        var provider = agGetCaptchaProvider();
        var key = provider === '2captcha' ? agGet2CaptchaKey() : agGetAntiCaptchaKey();
        if (!key) {
          statusEl.textContent = '❌ Configure a API key do provedor primeiro';
          statusEl.style.color = '#f87171'; return;
        }
        btn.disabled = true;
        btn.textContent = '⏳ Abrindo...';
        statusEl.textContent = '';

        // Determinar imagem: captcha ativo no jogo > imagem real do GitHub > sample base64
        var liveImg = document.getElementById('kintara-captcha-img');
        var _AG_CAPTCHA_REAL_URL = 'https://raw.githubusercontent.com/krokonskrafael-ai/dotagg/refs/heads/main/captcha.png';
        var imgSrc = (liveImg && liveImg.src && liveImg.src.indexOf('captcha') >= 0)
          ? liveImg.src
          : _AG_CAPTCHA_REAL_URL; // usa a imagem real do GitHub quando não há captcha ativo
        var isReal = true; // sempre é real agora (jogo ou GitHub)

        // Criar modal idêntico ao do jogo
        var existing = document.getElementById('ag-captcha-test-overlay');
        if (existing) existing.remove();

        // Injetar CSS do captcha do jogo (se não existir)
        if (!document.getElementById('ag-captcha-test-style')) {
          var styleEl = document.createElement('style');
          styleEl.id = 'ag-captcha-test-style';
          styleEl.textContent = [
            '#ag-captcha-test-overlay{position:fixed;inset:0;z-index:2147483647;display:flex;align-items:center;justify-content:center;',
            'background:rgba(4,6,12,0.93);pointer-events:auto;font-family:system-ui,"Segoe UI",Roboto,sans-serif}',
            '#ag-captcha-test-overlay .ag-ct-panel{width:min(320px,calc(100vw - 24px));box-sizing:border-box;',
            'background:#11151f;border:1px solid #2a3344;border-radius:10px;padding:16px 16px 14px;text-align:center;box-shadow:0 12px 40px rgba(0,0,0,0.6)}',
            '#ag-captcha-test-overlay .ag-ct-badge{display:inline-block;font-size:9px;font-weight:700;letter-spacing:.06em;',
            'background:rgba(251,191,36,0.15);border:1px solid rgba(251,191,36,0.35);color:#fbbf24;',
            'border-radius:4px;padding:2px 7px;margin-bottom:8px}',
            '#ag-captcha-test-overlay .ag-ct-title{font-size:14px;font-weight:800;color:#eef2f8;margin:0 0 4px}',
            '#ag-captcha-test-overlay .ag-ct-hint{font-size:10px;font-weight:600;line-height:1.45;color:#aeb7c6;margin:0 0 12px}',
            '#ag-captcha-test-overlay .ag-ct-img{display:block;margin:0 auto 12px;max-width:100%;height:auto;',
            'border-radius:6px;border:1px solid #2a3344;background:#e8edf6;image-rendering:pixelated}',
            '#ag-captcha-test-overlay .ag-ct-input{width:100%;box-sizing:border-box;padding:10px;font-size:18px;',
            'font-weight:700;letter-spacing:4px;text-align:center;text-transform:uppercase;',
            'border-radius:6px;border:1px solid #38445a;background:#0c0f17;color:#eef2f8;outline:none;margin:0 0 8px}',
            '#ag-captcha-test-overlay .ag-ct-status{min-height:14px;font-size:10px;font-weight:700;color:#aeb7c6;margin:0 0 4px}',
            '#ag-captcha-test-overlay .ag-ct-row{display:flex;gap:8px;margin-top:4px}',
            '#ag-captcha-test-overlay .ag-ct-btn{flex:1;padding:10px;font-size:13px;font-weight:800;',
            'border-radius:6px;cursor:pointer;border:none}',
            '#ag-captcha-test-overlay .ag-ct-btn-primary{background:#3b6fd6;color:#fff}',
            '#ag-captcha-test-overlay .ag-ct-btn-primary:disabled{opacity:0.5;cursor:default}',
            '#ag-captcha-test-overlay .ag-ct-btn-cancel{background:rgba(255,255,255,0.07);color:#8a93a8}',
          ].join('');
          document.head.appendChild(styleEl);
        }

        var overlay = document.createElement('div');
        overlay.id = 'ag-captcha-test-overlay';
        overlay.innerHTML = [
          '<div class="ag-ct-panel">',
            '<div class="ag-ct-badge">🧪 MODO TESTE — ' + (isReal ? 'imagem real' : 'imagem sample') + '</div>',
            '<div class="ag-ct-title">Verify you\u2019re human</div>',
            '<div class="ag-ct-hint">Simulação do captcha real. O solver ' + provider + ' vai tentar resolver automaticamente.</div>',
            '<img class="ag-ct-img" id="ag-ct-img" src="' + imgSrc + '" alt="captcha test">',
            '<input class="ag-ct-input" id="ag-ct-input" type="text" autocomplete="off" ',
              'autocapitalize="characters" spellcheck="false" maxlength="8" placeholder="...">',
            '<div class="ag-ct-status" id="ag-ct-status">Iniciando solver...</div>',
            '<div class="ag-ct-row">',
              '<button class="ag-ct-btn ag-ct-btn-primary" id="ag-ct-submit" disabled>Verificar</button>',
              '<button class="ag-ct-btn ag-ct-btn-cancel" id="ag-ct-close">Fechar</button>',
            '</div>',
          '</div>',
        ].join('');
        document.body.appendChild(overlay);

        var inputEl   = document.getElementById('ag-ct-input');
        var statusEl2 = document.getElementById('ag-ct-status');
        var submitEl  = document.getElementById('ag-ct-submit');

        // Fechar
        document.getElementById('ag-ct-close').addEventListener('click', function() {
          overlay.remove();
          btn.disabled = false; btn.textContent = '▶ Teste Real';
          statusEl.textContent = '🛑 Cancelado pelo usuário';
          statusEl.style.color = '#8a93a8';
        });

        // Submit manual
        submitEl.addEventListener('click', function() {
          statusEl2.textContent = '✅ Enviado manualmente: "' + inputEl.value + '"';
          statusEl.textContent = '✅ Enviado: "' + inputEl.value + '"';
          statusEl.style.color = '#6ee7a0';
          setTimeout(function() { overlay.remove(); }, 1200);
          btn.disabled = false; btn.textContent = '▶ Teste Real';
        });
        inputEl.addEventListener('keydown', function(e) {
          if (e.key === 'Enter') submitEl.click();
          e.stopPropagation();
        });

        // Rodar o solver automaticamente
        statusEl2.textContent = 'Solver ' + provider + ' processando...';
        try {
          var sol = provider === '2captcha'
            ? await agSolve2Captcha(isReal ? imgSrc : null, isReal ? null : _AG_AC_SAMPLE)
            : await agSolveAntiCaptcha(isReal ? imgSrc : null, isReal ? null : _AG_AC_SAMPLE);

          if (sol) {
            inputEl.value = sol.toUpperCase();
            inputEl.dispatchEvent(new Event('input', { bubbles: true }));
            submitEl.disabled = false;
            statusEl2.textContent = '✅ Solver resolveu: "' + sol + '" — confira e clique Verificar';
            statusEl.textContent = '✅ Resolvido: "' + sol + '"';
            statusEl.style.color = '#6ee7a0';
          } else {
            submitEl.disabled = false;
            statusEl2.textContent = '❌ Solver não resolveu — tente manualmente';
            statusEl.textContent = '❌ Solver falhou';
            statusEl.style.color = '#f87171';
          }
        } catch(e) {
          submitEl.disabled = false;
          statusEl2.textContent = '❌ Erro: ' + e.message;
          statusEl.textContent = '❌ Erro: ' + e.message;
          statusEl.style.color = '#f87171';
        }

        btn.disabled = false;
        btn.textContent = '▶ Teste Real';
      });
    }

    // Salvar checkbox auto
    if ($('ag-cfg-anticaptcha-auto')) {
      $('ag-cfg-anticaptcha-auto').addEventListener('change', function() {
        try {
          localStorage.setItem('kintara_ag_anticaptcha_auto', this.checked ? 'true' : 'false');
        } catch(_) {}
      });
    }

    // Colapso/expansão seção Boss
    makeCollapsible('ag-boss-hdr', 'ag-boss-body', 'ag-boss-chev');
    // Boss começa colapsado (sem classe open)

    // Restaurar cfg salvo do Boss
    (function() {
      try {
        var cfg = JSON.parse(localStorage.getItem('kintara_ag_boss_cfg') || '{}');
        if (cfg.health   && $('ag-boss-potion-health-check'))   $('ag-boss-potion-health-check').checked   = true;
        if (cfg.shield   && $('ag-boss-potion-shield-check'))   $('ag-boss-potion-shield-check').checked   = true;
        if (cfg.strength && $('ag-boss-potion-strength-check')) $('ag-boss-potion-strength-check').checked = true;
        if (cfg.hpThresh   && $('ag-boss-hp-thresh'))     $('ag-boss-hp-thresh').value     = String(cfg.hpThresh);
        if (cfg.shieldThresh && $('ag-boss-shield-thresh')) $('ag-boss-shield-thresh').value = String(cfg.shieldThresh);
        // attack check: default true — só desmarca se explicitamente false
        if ($('ag-boss-attack-mini-check')) $('ag-boss-attack-mini-check').checked = cfg.attackMini !== false;
        if (cfg.safeSpot && $('ag-boss-safe-spot')) $('ag-boss-safe-spot').value = cfg.safeSpot;
      } catch(_) {}
    })();

    // Salvar cfg Boss quando checkboxes mudam
    ['ag-boss-potion-health-check','ag-boss-potion-shield-check','ag-boss-potion-strength-check',
     'ag-boss-hp-thresh','ag-boss-shield-thresh','ag-boss-attack-mini-check','ag-boss-safe-spot'].forEach(function(id) {
      var el = $(id);
      if (el) el.addEventListener('change', function() {
        try {
          localStorage.setItem('kintara_ag_boss_cfg', JSON.stringify({
            health:      !!($('ag-boss-potion-health-check')   && $('ag-boss-potion-health-check').checked),
            shield:      !!($('ag-boss-potion-shield-check')   && $('ag-boss-potion-shield-check').checked),
            strength:    !!($('ag-boss-potion-strength-check') && $('ag-boss-potion-strength-check').checked),
            hpThresh:    Number($('ag-boss-hp-thresh')     && $('ag-boss-hp-thresh').value)     || 3,
            shieldThresh:Number($('ag-boss-shield-thresh') && $('ag-boss-shield-thresh').value) || 2,
            attackMini:  !!($('ag-boss-attack-mini-check') && $('ag-boss-attack-mini-check').checked),
            safeSpot:    $('ag-boss-safe-spot') ? $('ag-boss-safe-spot').value : 'SE',
          }));
        } catch(_) {}
      });
    });
    // Restaura opcoes de caça
    try {
      var _hcfg = JSON.parse(localStorage.getItem('kintara_ag_hunt_cfg') || '{}');
      if (_hcfg.radius   && $('ag-hunt-radius-check'))   $('ag-hunt-radius-check').checked   = true;
      if (_hcfg.kite     && $('ag-hunt-kite-check'))     $('ag-hunt-kite-check').checked     = true;
      if (_hcfg.godMode  && $('ag-godmode-check'))        { $('ag-godmode-check').checked = true; window.__agGodMode = true; }
      if (_hcfg.health   && $('ag-potion-health-check'))  $('ag-potion-health-check').checked  = true;
      if (_hcfg.shield   && $('ag-potion-shield-check'))  $('ag-potion-shield-check').checked  = true;
      if (_hcfg.strength && $('ag-potion-strength-check')) $('ag-potion-strength-check').checked = true;
      if (_hcfg.hpThresh    && $('ag-hunt-hp-thresh'))     $('ag-hunt-hp-thresh').value     = String(_hcfg.hpThresh);
      if (_hcfg.shieldThresh && $('ag-hunt-shield-thresh')) $('ag-hunt-shield-thresh').value = String(_hcfg.shieldThresh);
    } catch(_) {}
    function agSaveHuntCfg() {
      try {
        localStorage.setItem('kintara_ag_hunt_cfg', JSON.stringify({
          radius:      !!($('ag-hunt-radius-check')    && $('ag-hunt-radius-check').checked),
          kite:        !!($('ag-hunt-kite-check')      && $('ag-hunt-kite-check').checked),
          godMode:     !!($('ag-godmode-check')         && $('ag-godmode-check').checked),
          health:      !!($('ag-potion-health-check')  && $('ag-potion-health-check').checked),
          shield:      !!($('ag-potion-shield-check')  && $('ag-potion-shield-check').checked),
          strength:    !!($('ag-potion-strength-check') && $('ag-potion-strength-check').checked),
          hpThresh:    Number($('ag-hunt-hp-thresh')     && $('ag-hunt-hp-thresh').value)     || 3,
          shieldThresh:Number($('ag-hunt-shield-thresh') && $('ag-hunt-shield-thresh').value) || 2,
        }));
      } catch(_) {}
    }
    ['ag-hunt-radius-check','ag-hunt-kite-check','ag-godmode-check','ag-potion-health-check','ag-potion-shield-check',
     'ag-potion-strength-check','ag-hunt-hp-thresh','ag-hunt-shield-thresh'].forEach(function(id) {
      if ($(id)) $(id).addEventListener('change', function(e) {
        agSaveHuntCfg();
        // GodMode toggle
        if (id === 'ag-godmode-check') {
          window.__agGodMode = e.target.checked;
          AG_LOG.info('[GodMode] ' + (window.__agGodMode ? 'ATIVADO' : 'DESATIVADO'));
        }
      });
    });

    // ── AUTO-VENDA section ────────────────────────────────────────────────────

    // ── DONATE ───────────────────────────────────────────────────────────────
    (function() {
      var DONATE_KEY   = 'kintara_ag_merch_donate';
      var DONATE_ITEMS = [
        { type:'wood',             label:'Wood'        },
        { type:'stone',            label:'Stone'       },
        { type:'coal',             label:'Coal'        },
        { type:'cooked_fish_meat', label:'Cooked Fish' },
        { type:'metal',            label:'Metal'       },
      ];
      // Merchant world position (col=21, row=11) — tile adjacente abaixo (row 12)
      var AG_MERCH_COL = 21;
      var AG_MERCH_ROW = 12; // tile adjacente ao merchant

      function loadDonateCfg() { try { return JSON.parse(localStorage.getItem(DONATE_KEY)||'{}'); } catch(_) { return {}; } }
      function saveDonateCfg(c) { try { localStorage.setItem(DONATE_KEY, JSON.stringify(c)); } catch(_) {} }

      function getCurrentCycleId() {
        try {
          var raw = localStorage.getItem(DONATE_KEY);
          var parsed = raw ? JSON.parse(raw) : {};
          var keys = Object.keys(parsed).filter(function(k) { return /^\d+$/.test(k); }).map(Number);
          return keys.length ? Math.max.apply(null, keys) : null;
        } catch(_) { return null; }
      }

      function getDonated(cycleId, type) {
        if (!cycleId) return 0;
        return (loadDonateCfg()[cycleId] || {})[type] || 0;
      }

      function getTarget(cycleId, type) {
        if (!cycleId) return 0;
        return (loadDonateCfg()[cycleId] || {})['target_' + type] || 0;
      }

      function getHaveCount(type) {
        try {
          if (typeof Jt !== 'undefined' && Jt[type] != null) return Jt[type] | 0;
          var total = 0;
          for (var i = 0; i < 24; i++) { var s = st[i]; if (s && s.type === type) total += (s.count||0); }
          return total;
        } catch(_) { return 0; }
      }

      function getPanelRoot() {
        var m = document.getElementById('ag-panel-host');
        return m && m.shadowRoot;
      }

      // Cache da fase do merchant (atualizado via API)
      var _donatePhaseCache = null;
      var _donatePhaseLastFetch = 0;

      async function fetchDonatePhase() {
        try {
          var now = Date.now();
          if (now - _donatePhaseLastFetch < 15000) return _donatePhaseCache;
          _donatePhaseLastFetch = now;
          var r = await fetch('/api/auth/merchant-cycle-status', { credentials: 'include' });
          var d = await r.json().catch(function(){ return {}; });
          _donatePhaseCache = d && d.phase ? d.phase : null;
          return _donatePhaseCache;
        } catch(_) { return _donatePhaseCache; }
      }

      function isDonatePhase() {
        // Verificar pelo cache ou pelo merchant HUD aberto
        if (_donatePhaseCache) return _donatePhaseCache === 'donate';
        // Fallback: goldTradeEnabled via dados locais do bundle
        try { return !!(typeof merchantGoldTradeEnabledFromServer === 'function' && merchantGoldTradeEnabledFromServer()); } catch(_) {}
        return false;
      }

      // Verifica se TODOS os itens com target>0 têm quantidade suficiente ce fase é donate
      function donateReadyCheck() {
        if (!isDonatePhase()) return false;
        var cycleId = getCurrentCycleId();
        var ready = true, anyTarget = false;
        for (var i = 0; i < DONATE_ITEMS.length; i++) {
          var item = DONATE_ITEMS[i];
          var target = getTarget(cycleId, item.type);
          if (target <= 0) continue;
          anyTarget = true;
          var have = getHaveCount(item.type);
          if (have < target) { ready = false; break; }
        }
        return anyTarget && ready;
      }

      function loadDonateInputs() {
        var cycleId = getCurrentCycleId();
        var pr = getPanelRoot();
        var $ = function(id) { return pr && pr.getElementById(id); };
        DONATE_ITEMS.forEach(function(item) {
          var inp = $('ag-don-' + item.type);
          if (inp) inp.value = getTarget(cycleId, item.type) || '';
        });
        updateDonateInfo();
      }

      function updateDonateInfo() {
        var cycleId = getCurrentCycleId();
        var pr = getPanelRoot();
        var $ = function(id) { return pr && pr.getElementById(id); };
        var allReady = true, anyTarget = false;
        DONATE_ITEMS.forEach(function(item) {
          var el = $('ag-don-info-' + item.type);
          if (!el) return;
          var have    = getHaveCount(item.type);
          var donated = getDonated(cycleId, item.type);
          var target  = getTarget(cycleId, item.type);
          if (target > 0) {
            anyTarget = true;
            if (have < target) allReady = false;
          }
          var haveColor   = (target > 0 && have >= target) ? '#6ee7a0' : '#d4d8e2';
          var doneColor   = (donated >= target && target > 0) ? '#6ee7a0' : '#64748b';
          el.innerHTML = 'Tenho: <b style="color:' + haveColor + '">' + have.toLocaleString() + '</b>'
                       + ' · Doei: <b style="color:' + doneColor + '">' + donated.toLocaleString() + '</b>'
                       + (target > 0 ? '/<span style="color:#8a93a8">' + target.toLocaleString() + '</span>' : '');
        });
        // Atualizar status do botão
        var btn = $('ag-donate-now-btn');
        var cancelBtn = $('ag-donate-cancel-btn');
        if (btn && !btn._agDonating) {
          var phase = isDonatePhase();
          var ready = phase && anyTarget && allReady;
          btn.style.background = ready ? 'rgba(251,191,36,0.25)' : 'rgba(251,191,36,0.08)';
          btn.style.color      = ready ? '#fbbf24' : '#64748b';
          btn.style.borderColor= ready ? 'rgba(251,191,36,0.5)' : 'rgba(251,191,36,0.15)';
          if (!phase) btn.textContent = '⏸ Fase: Claim (sem doações)';
          else if (!anyTarget) btn.textContent = '⏳ Configure quantidades acima';
          else if (!allReady) btn.textContent = '⏳ Aguardando recursos…';
          else btn.textContent = '🏅 Pronto! Ir ao Merchant';
          btn.disabled = false;
        }
        if (cancelBtn) cancelBtn.style.display = 'none';
        var resEl = $('ag-donate-result');
        if (resEl && !resEl._agMsg) {
          if (!anyTarget) {
            resEl.textContent = 'Configure quanto deseja doar acima';
            resEl.style.color = '#475569';
          } else if (!allReady) {
            // Mostrar quais faltam
            var missing = [];
            for (var i = 0; i < DONATE_ITEMS.length; i++) {
              var it = DONATE_ITEMS[i];
              var tgt = getTarget(cycleId, it.type);
              if (tgt <= 0) continue;
              var hv = getHaveCount(it.type);
              if (hv < tgt) missing.push(it.label + ': ' + hv.toLocaleString() + '/' + tgt.toLocaleString());
            }
            resEl.textContent = '⏳ Faltam: ' + missing.join(' | ');
            resEl.style.color = '#f59e0b';
          } else {
            resEl.textContent = '✅ Todos os recursos prontos!';
            resEl.style.color = '#6ee7a0';
          }
        }
      }

      // Salvar target ao mudar input
      DONATE_ITEMS.forEach(function(item) {
        var $ = function(id) { var pr=getPanelRoot(); return pr && pr.getElementById(id); };
        setTimeout(function() {
          var inp = $('ag-don-' + item.type);
          if (!inp) return;
          inp.addEventListener('change', function() {
            var cycleId = getCurrentCycleId() || Date.now();
            var cfg = loadDonateCfg();
            if (!cfg[cycleId]) cfg[cycleId] = {};
            cfg[cycleId]['target_' + item.type] = Math.max(0, parseInt(inp.value)||0);
            saveDonateCfg(cfg);
            updateDonateInfo();
          });
        }, 100);
      });

      // ── Fluxo de doação: para farm → vai ao merchant → doa → volta → retoma ──
      var _agDonating = false;

      async function agDonateMerchantFlow() {
        if (_agDonating) return;
        var pr = getPanelRoot();
        var $ = function(id) { return pr && pr.getElementById(id); };
        var btn       = $('ag-donate-now-btn');
        var cancelBtn = $('ag-donate-cancel-btn');
        var resEl = $('ag-donate-result');

        // Verificar fase donate
        var phase = await fetchDonatePhase();
        if (phase !== 'donate') {
          if (resEl) { resEl._agMsg = true; resEl.textContent = '⏸ Merchant não está em fase de doação (fase: ' + (phase || '?') + ')'; resEl.style.color = '#f59e0b'; resEl._agMsg = false; }
          _agDonating = false;
          if (btn) { btn._agDonating = false; btn.disabled = false; }
          return;
        }
        // Verificar se os recursos estão todos OK
        if (!donateReadyCheck()) {
          if (resEl) { resEl._agMsg = true; resEl.textContent = '⏳ Recursos insuficientes ainda'; resEl.style.color = '#f59e0b'; resEl._agMsg = false; }
          _agDonating = false;
          if (btn) { btn._agDonating = false; btn.disabled = false; }
          return;
        }

        _agDonating = true;
        if (btn) { btn._agDonating = true; btn.disabled = true; btn.textContent = '🚶 Indo ao Merchant…'; }
        if (cancelBtn) cancelBtn.style.display = 'inline-block';
        if (resEl) { resEl._agMsg = true; resEl.textContent = '⏳ Parando farm…'; resEl.style.color = '#8a93a8'; }

        // 1. Salvar estado do farm e parar
        var wasActive  = agActive;
        var savedRealm = m; // gameState atual
        if (wasActive) agStop();

        // 2. Se não estiver no world, voltar ao world primeiro
        if (D!=='world') {
          if (resEl) resEl.textContent = '🚶 Voltando ao World…';
          agNavTo('world');
          // Aguardar chegada ao world (max 30s)
          var _navWait = 0;
          while (D!=='world' && _navWait < 60 && !_agCancelDonate) {
            await new Promise(function(r){ setTimeout(r, 500); });
            _navWait++;
          }
          agNavCancel();
          if (D!=='world') {
            if (resEl) { resEl.textContent = '✗ Não consegui chegar ao World'; resEl.style.color = '#f87171'; }
            _donateCleanup(btn, resEl, wasActive, savedRealm);
            return;
          }
        }

        // 3. Navegar até o tile adjacente ao merchant
        if (resEl) resEl.textContent = '🚶 Indo ao Merchant (col=' + AG_MERCH_COL + ', row=' + AG_MERCH_ROW + ')…';
        var path = r(ce, de, AG_MERCH_COL, AG_MERCH_ROW);
        if (path && path.length) {
          qe = path; if (!$e) Ll();
        }
        // Aguardar chegada (max 20s)
        var _walkWait = 0;
        while ((Math.abs(ce - AG_MERCH_COL) > 1 || Math.abs(de - AG_MERCH_ROW) > 1) && _walkWait < 40 && !_agCancelDonate) {
          await new Promise(function(r){ setTimeout(r, 500); });
          _walkWait++;
        }

        // 4. Verificar se chegou perto o suficiente
        var dist = Math.abs(ce - AG_MERCH_COL) + Math.abs(de - AG_MERCH_ROW);
        if (dist > 3) {
          if (resEl) { resEl.textContent = '✗ Não consegui chegar ao Merchant (dist=' + dist + ')'; resEl.style.color = '#f87171'; }
          _donateCleanup(btn, resEl, wasActive, savedRealm);
          return;
        }

        // 5. Verificar cancelamento
        if (_agCancelDonate) { _donateCleanup(btn, cancelBtn, wasActive, savedRealm); return; }

        // 6. Fazer as doações
        if (resEl) resEl.textContent = '💰 Doando recursos…';
        var cycleId = getCurrentCycleId() || 0;
        var donated = [], errors = [];

        for (var i = 0; i < DONATE_ITEMS.length; i++) {
          var item   = DONATE_ITEMS[i];
          var target = getTarget(cycleId, item.type);
          var have   = getHaveCount(item.type);
          if (target <= 0 || have < target) continue;

          try {
            try { cn({ inventoryMutationFlush: true }); } catch(_) {}
            var r = await fetch('/api/auth/merchant-trade-for-gold', {
              method:'POST', credentials:'include',
              headers:{'Content-Type':'application/json'}, body:'{}',
            });
            var d = await r.json().catch(function(){ return {}; });
            if (r.ok && d.ok !== false) {
              var cfg = loadDonateCfg();
              if (!cfg[cycleId]) cfg[cycleId] = {};
              cfg[cycleId][item.type] = (cfg[cycleId][item.type]||0) + target;
              saveDonateCfg(cfg);
              donated.push(item.label + ' ×' + target.toLocaleString());
            } else {
              errors.push(item.label + ': ' + (d.error || 'erro'));
            }
          } catch(e) { errors.push(item.label + ': ' + e.message); }
          await new Promise(function(r2){ setTimeout(r2, 800); });
        }

        // 6. Mostrar resultado
        if (donated.length) {
          if (resEl) { resEl.textContent = '✓ Doado: ' + donated.join(', '); resEl.style.color = '#6ee7a0'; }
          AG_LOG.info('[Donate] Concluído: ' + donated.join(', '));
        } else if (errors.length) {
          if (resEl) { resEl.textContent = '✗ ' + errors[0]; resEl.style.color = '#f87171'; }
        }

        // 7. Voltar ao realm e retomar farm
        await new Promise(function(r){ setTimeout(r, 1500); });
        _donateCleanup(btn, resEl, wasActive, savedRealm);
      }

      var _agCancelDonate = false;

      function _donateCleanup(btn, resEl, wasActive, savedRealm) {
        _agDonating = false;
        _agCancelDonate = false;
        if (btn) { btn._agDonating = false; btn.disabled = false; }
        var pr2 = getPanelRoot();
        var cb = pr2 && pr2.getElementById('ag-donate-cancel-btn');
        if (cb) cb.style.display = 'none';
        if (resEl) resEl._agMsg = false;

        // Voltar ao realm que estava farmando
        if (savedRealm && savedRealm !== 'world' && m !== savedRealm) {
          AG_LOG.info('[Donate] Voltando ao realm: ' + savedRealm);
          agNavTo(savedRealm);
        }

        // Retomar farm após chegar ao realm (ou imediatamente se world)
        if (wasActive) {
          if (savedRealm === 'world' || !savedRealm) {
            setTimeout(function() { if (!agActive) agStart(); }, 1000);
          } else {
            // Esperar chegar ao realm
            var _retryCount = 0;
            var _retryTimer = setInterval(function() {
              _retryCount++;
              if (m === savedRealm || _retryCount > 60) {
                clearInterval(_retryTimer);
                if (!agActive) { agStart(); AG_LOG.info('[Donate] Farm retomado em ' + D); }
              }
            }, 500);
          }
        }
        updateDonateInfo();
      }

      // Listener do botão
      setTimeout(function() {
        var $ = function(id) { var pr=getPanelRoot(); return pr && pr.getElementById(id); };
        var btn = $('ag-donate-now-btn');
        if (btn) btn.addEventListener('click', function() { if (!_agDonating) agDonateMerchantFlow(); });
        var cancelBtn = $('ag-donate-cancel-btn');
        if (cancelBtn) cancelBtn.addEventListener('click', function() {
          if (!_agDonating) return;
          _agCancelDonate = true;
          cancelBtn.disabled = true;
          cancelBtn.textContent = '⏳';
          var pr = getPanelRoot();
          var resEl = pr && pr.getElementById('ag-donate-result');
          if (resEl) { resEl.textContent = '🛑 Cancelando…'; resEl.style.color = '#f87171'; }
          AG_LOG.warn('[Donate] Cancelado pelo usuário');
        });
      }, 200);

      // Auto-atualizar info a cada 5s
      var _donIv = setInterval(function() {
        if (!document.getElementById('ag-panel-host')) { clearInterval(_donIv); return; }
        updateDonateInfo();
        // Auto-disparar se recursos prontos, farm ativo e fase donate
        if (!_agDonating && isDonatePhase() && donateReadyCheck() && agActive) {
          AG_LOG.info('[Donate] Recursos prontos — iniciando fluxo de doação automático');
          agDonateMerchantFlow();
        }
        // Atualizar cache de fase periodicamente
        fetchDonatePhase();
      }, 5000);


      // ── Buy Personal Gold ─────────────────────────────────────────────────
      var AG_BPG_KEY = 'kintara_ag_buy_personal_gold';

      function bpgEnabled() {
        var pr = getPanelRoot();
        var chk = pr && pr.getElementById('ag-buy-personal-gold-chk');
        return chk && chk.checked;
      }

      function bpgSave(enabled) {
        try { localStorage.setItem(AG_BPG_KEY, enabled ? '1' : '0'); } catch(_) {}
      }

      function bpgLoad() {
        try { return localStorage.getItem(AG_BPG_KEY) === '1'; } catch(_) { return false; }
      }

      // Verifica daily quests — retorna { done: N, total: N, allDone: bool, ids: [] }
      async function checkDailyQuests() {
        try {
          // Usar estado local ya (bundle minificado)
          var localDone = 0, localTotal = 0;
          try {
            var claimed = ya && Sa.claimed;
            if (claimed) {
              var keys = Object.keys(claimed);
              localTotal = keys.length;
              localDone  = keys.filter(function(k){ return claimed[k]; }).length;
            }
          } catch(_) {}

          // Também buscar via API para garantir dados frescos
          var r = await fetch('/api/auth/daily-quest-progress', {
            method: 'POST', credentials: 'include',
            headers: {'Content-Type': 'application/json'},
            body: '{}',
          });
          var d = await r.json().catch(function(){ return {}; });

          if (d.ok && d.dailyQuest) {
            var dq = d.dailyQuest;
            var claimed2 = dq.claimed || {};
            var allIds = dq.config ? (dq.config.quests || []).map(function(U){ return U.id; }) : Object.keys(claimed2);
            localTotal = allIds.length || localTotal;
            localDone  = allIds.filter(function(id){ return claimed2[id]; }).length;
          }

          return { done: localDone, total: localTotal || 3, allDone: localDone >= (localTotal || 3) };
        } catch(e) {
          // Fallback: usar ya local
          try {
            var claimed = ya && Sa.claimed || {};
            var keys = Object.keys(claimed);
            var done = keys.filter(function(k){ return claimed[k]; }).length;
            return { done: done, total: Math.max(keys.length, 3), allDone: done >= 3 };
          } catch(_) { return { done: 0, total: 3, allDone: false }; }
        }
      }

      // Verificar merchant cycle status e cap
      async function checkMerchantReady() {
        try {
          var r1 = await fetch('/api/auth/merchant-cycle-status', {credentials:'include'});
          var r2 = await fetch('/api/auth/merchant-cap-status',   {credentials:'include'});
          var cycle = await r1.json().catch(function(){ return {}; });
          var cap   = await r2.json().catch(function(){ return {}; });
          return {
            phase:       cycle.phase,
            myAvailable: cycle.myAvailable || 0,
            capRemaining: cap.remaining || 0,
            capUsed:      cap.used || 0,
            capTotal:     cap.cap || 0,
          };
        } catch(_) { return { phase: null, myAvailable: 0, capRemaining: 0 }; }
      }

      // Atualizar painel de status
      async function updatePersonalGoldStatus() {
        var pr = getPanelRoot();
        var statusEl = pr && pr.getElementById('ag-personal-gold-status');
        var btn      = pr && pr.getElementById('ag-personal-gold-btn');
        if (!statusEl) return;

        statusEl.textContent = '🔄 Verificando…';

        var quests  = await checkDailyQuests();
        var merch   = await checkMerchantReady();

        var lines = [];

        // Daily quests
        var questColor = quests.allDone ? '#6ee7a0' : '#f87171';
        lines.push('<span style="color:' + questColor + '">Daily Quests: ' + quests.done + '/' + quests.total + (quests.allDone ? ' ✓' : ' ✗') + '</span>');

        // Fase do merchant
        var phaseColor = merch.phase === 'claim' ? '#6ee7a0' : '#f59e0b';
        lines.push('<span style="color:' + phaseColor + '">Fase: ' + (merch.phase || '?') + '</span>');

        // Gold disponível
        var goldColor = merch.myAvailable > 0 ? '#6ee7a0' : '#f87171';
        lines.push('<span style="color:' + goldColor + '">Personal Gold: ' + merch.myAvailable + ' disponível</span>');

        // Cap diário
        var capColor = merch.capRemaining > 0 ? '#6ee7a0' : '#f87171';
        lines.push('<span style="color:' + capColor + '">Cap: ' + merch.capUsed + '/' + merch.capTotal + (merch.capRemaining > 0 ? ' ✓' : ' ✗') + '</span>');

        statusEl.innerHTML = lines.join(' · ');

        // Habilitar botão apenas se tudo OK
        var canClaim = quests.allDone && merch.phase === 'claim' && merch.myAvailable > 0 && merch.capRemaining > 0;
        if (btn) {
          btn.disabled = !canClaim;
          btn.style.background = canClaim ? 'rgba(110,231,160,0.2)' : 'rgba(100,116,139,0.1)';
          btn.style.color      = canClaim ? '#6ee7a0' : '#64748b';
          btn.textContent      = canClaim
            ? '🎉 Claimar ' + merch.myAvailable + ' Gold'
            : (!quests.allDone ? '⏸ Aguardando quests (' + quests.done + '/' + quests.total + ')' : merch.phase !== 'claim' ? '⏸ Fase: ' + (merch.phase||'?') : merch.myAvailable <= 0 ? '⏸ Sem gold pessoal' : '⏸ Cap atingido');
        }
      }

      // Ação: Claimar Personal Gold
      async function doClaimPersonalGold() {
        var pr = getPanelRoot();
        var btn    = pr && pr.getElementById('ag-personal-gold-btn');
        var statusEl = pr && pr.getElementById('ag-personal-gold-status');

        if (btn) btn.disabled = true;
        if (statusEl) { statusEl.innerHTML = '⏳ Claimando…'; }

        try {
          // Verificar quests antes de tentar
          var quests = await checkDailyQuests();
          if (!quests.allDone) {
            if (statusEl) statusEl.innerHTML = '<span style="color:#f87171">✗ Quests não concluídas (' + quests.done + '/' + quests.total + ')</span>';
            if (btn) btn.disabled = false;
            return;
          }

          var merch = await checkMerchantReady();
          if (merch.phase !== 'claim') {
            if (statusEl) statusEl.innerHTML = '<span style="color:#f59e0b">✗ Merchant não está em fase claim (atual: ' + merch.phase + ')</span>';
            if (btn) btn.disabled = false;
            return;
          }
          if (merch.myAvailable <= 0) {
            if (statusEl) statusEl.innerHTML = '<span style="color:#f87171">✗ Sem gold pessoal disponível</span>';
            if (btn) btn.disabled = false;
            return;
          }
          if (merch.capRemaining <= 0) {
            if (statusEl) statusEl.innerHTML = '<span style="color:#f87171">✗ Cap diário atingido (' + merch.capUsed + '/' + merch.capTotal + ')</span>';
            if (btn) btn.disabled = false;
            return;
          }

          // Fazer claim
          var r = await fetch('/api/auth/merchant-claim-cycle-gold', {
            method: 'POST', credentials: 'include',
            headers: {'Content-Type': 'application/json'},
            body: JSON.stringify({ amount: merch.myAvailable }),
          });
          var d = await r.json().catch(function(){ return {}; });

          if (r.ok && d.ok !== false) {
            if (statusEl) statusEl.innerHTML = '<span style="color:#6ee7a0">✓ +' + (d.goldGranted || merch.myAvailable) + ' Gold claimado!</span>';
          } else {
            var msg = d.error === 'no_contribution'    ? 'Sem contribuição pessoal'
                    : d.error === 'cycle_not_complete' ? 'Ciclo não completo'
                    : d.error === 'merchant_daily_cap' ? 'Cap diário atingido'
                    : d.error === 'already_claimed'    ? 'Já claimado hoje'
                    : (d.error || 'Erro desconhecido');
            if (statusEl) statusEl.innerHTML = '<span style="color:#f87171">✗ ' + msg + '</span>';
          }
        } catch(e) {
          if (statusEl) statusEl.innerHTML = '<span style="color:#f87171">✗ Erro: ' + e.message + '</span>';
        }

        // Atualizar status após 2s
        setTimeout(updatePersonalGoldStatus, 2000);
      }

      // Listeners do Personal Gold
      setTimeout(function() {
        var pr = getPanelRoot();
        var chk = pr && pr.getElementById('ag-buy-personal-gold-chk');
        var btn = pr && pr.getElementById('ag-personal-gold-btn');

        if (chk) {
          chk.checked = bpgLoad();
          chk.addEventListener('change', function() {
            bpgSave(chk.checked);
            if (chk.checked) updatePersonalGoldStatus();
          });
          // Auto-verificar ao abrir se estava marcado
          if (chk.checked) setTimeout(updatePersonalGoldStatus, 300);
        }

        if (btn) {
          btn.addEventListener('click', doClaimPersonalGold);
        }
      }, 300);

      // Auto-verificar a cada 60s se checkbox marcado
      setInterval(function() {
        if (!document.getElementById('ag-panel-host')) return;
        if (bpgEnabled()) updatePersonalGoldStatus();
      }, 60000);

      loadDonateInputs();
    })();

    makeCollapsible('ag-sell-hdr', 'ag-sell-body', 'ag-sell-chev');

