    agAutoGoldBuying = true;
    AG_LOG.info('AutoGold: tentando comprar | modo=' + (merchantGoldCampaign && merchantGoldCampaign.mode) +
      ' stock=' + (merchantGoldCampaign && merchantGoldCampaign.goldStock));

