        if (d.backpack) { try { applyServerAuthoritativeBackpack(d.backpack, { flush: false, stateSeq: d.stateSeq }); } catch(_) {} }
        if (d.campaign) { try { applyMerchantGoldCampaignFromServer(d.campaign); } catch(_) {} }
        agAutoGoldBuying = false;
