  // ── agHarvestDebug() — monitora coleta manual para entender o fluxo real ──
  var _agHDbActive    = false;
  var _agHDbOrigSend  = null;
  var _agHDbHitCount  = 0;
  var _agHDbLastHitAt = 0;
  var _agHDbLastProof = {};  // key → último proof visto
  var _agHDbLog       = [];  // histórico da sessão

  function agHarvestDebug(durationSec) {
    if (_agHDbActive) {
      // Segunda chamada — mostra relatório e para
      agHarvestDebugStop();
      return;
    }
    var dur = (typeof durationSec === 'number' && durationSec > 0) ? durationSec : 30;
    _agHDbActive   = true;
    _agHDbHitCount = 0;
    _agHDbLastHitAt = 0;
    _agHDbLastProof = {};
    _agHDbLog = [];

    console.group('%c[HarvestDebug] Monitorando por ' + dur + 's — colete recursos normalmente', 'color:#f59e0b;font-weight:bold');
    console.info('Chame agHarvestDebug() novamente para parar antes do tempo e ver o relatório');
    console.groupEnd();

    // Intercepta sendHarvestHit para logar cada chamada
    if (typeof sendHarvestHit === 'function' && !_agHDbOrigSend) {
      _agHDbOrigSend = sendHarvestHit;
      /* sendHarvestHit intercept N/A in minified bundle */
  if(false) sendHarvestHit = function(kind, keys, hasCoal, hasMetal) {
        if (_agHDbActive) {
          var now = Date.now();
          var pk  = keys && keys[0];
          var ctx, rec, proof = '';
          try {
            ctx = R3();
            rec = kind === 'rock'
              ? (ctx && ctx.rockMap && ctx.rockMap.get(pk))
              : (ctx && ctx.treeMap && ctx.treeMap.get(pk));
            proof = (rec && typeof rec.actionProof === 'string') ? rec.actionProof : '';
          } catch(_) {}

          var interval = _agHDbLastHitAt ? (now - _agHDbLastHitAt) : null;
          var proofChanged = pk && (_agHDbLastProof[pk] !== proof);
          _agHDbHitCount++;
          _agHDbLastHitAt = now;
          if (pk) _agHDbLastProof[pk] = proof;

          var entry = {
            n:        _agHDbHitCount,
            kind:     kind,
            key:      pk,
            proof:    proof ? proof.slice(0,12) + '...' : '(none)',
            proofNew: proofChanged,
            interval: interval,
            mTimer:   _agMineState   === 'mining'   ? +Z0.toFixed(3)   : null,
            cTimer:   _agChopState === 'chopping' ? +Vy.toFixed(3) : null,
          };
          _agHDbLog.push(entry);

          var style = proofChanged ? 'color:#6ee7a0' : 'color:#f87171';
          var mark  = proofChanged ? '✅' : '⚠️';
          console.log(
            '%c' + mark + ' hit#' + _agHDbHitCount +
            ' | ' + kind + ' [' + pk + ']' +
            ' | interval=' + (interval !== null ? interval + 'ms' : 'first') +
            ' | proof=' + (proof ? proof.slice(0,8) + '..' : 'none') + (proofChanged ? ' (novo)' : ' (mesmo)') +
            (entry.mTimer !== null ? ' | mTimer=' + entry.mTimer : '') +
            (entry.cTimer !== null ? ' | cTimer=' + entry.cTimer : ''),
            style
          );
        }
        return _agHDbOrigSend.apply(this, arguments);
      };
    }

    // Para automaticamente após dur segundos
    setTimeout(agHarvestDebugStop, dur * 1000);
  }

  function agHarvestDebugStop() {
    if (!_agHDbActive) return;
    _agHDbActive = false;

    // Restaura sendHarvestHit original
    if (_agHDbOrigSend) { sendHarvestHit = _agHDbOrigSend; _agHDbOrigSend = null; }

    // Relatório
    var total    = _agHDbLog.length;
    var newProof = _agHDbLog.filter(function(e) { return e.proofNew; }).length;
    var noProof  = _agHDbLog.filter(function(e) { return e.proof === '(none)'; }).length;
    var intervals = _agHDbLog.map(function(e) { return e.interval; }).filter(function(x) { return x !== null; });
    var avgInterval = intervals.length
      ? Math.round(intervals.reduce(function(a,b){return a+b;},0) / intervals.length)
      : 0;
    var minInterval = intervals.length ? Math.min.apply(null, intervals) : 0;
    var maxInterval = intervals.length ? Math.max.apply(null, intervals) : 0;

    console.group('%c[HarvestDebug] Relatório final', 'color:#f59e0b;font-weight:bold');
    console.info('Total de hits enviados : ' + total);
    console.info('Com proof novo (aceito): ' + newProof + ' (' + Math.round(newProof/Math.max(1,total)*100) + '%)');
    console.info('Sem proof (1º hit / miss): ' + noProof);
    console.info('Intervalo entre hits   : min=' + minInterval + 'ms | avg=' + avgInterval + 'ms | max=' + maxInterval + 'ms');
    console.info('');
    console.info('Hits com proof=mesmo (possível rejeição pelo servidor):',
      _agHDbLog.filter(function(e){ return !e.proofNew && e.proof !== '(none)' && e.n > 1; }).length);
    console.info('');
    console.info('Log completo em window._agHDbLog');
    console.groupEnd();

    window._agHDbLog = _agHDbLog;
  }

  try { globalThis.agHarvestDebug = agHarvestDebug; } catch(_) {}
